// ==========================================
// 6. VISTAS E INTERFAZ GRÁFICA (views.js) - COMPLETO Y CORREGIDO
// ==========================================

App.views.login = function() { return `<div style="display:flex; flex-direction:column; align-items:center; justify-content:center; height:80vh; text-align:center;"><div style="background:var(--primary); color:white; width:80px; height:80px; border-radius:50%; display:flex; align-items:center; justify-content:center; font-size:2rem; margin-bottom:20px;">🔒</div><h2 style="margin-bottom:10px; color:var(--primary-dark);">Descanso Maya</h2><p style="color:var(--text-muted); margin-bottom:30px;">Ingresa el PIN</p><div class="card" style="width:100%; max-width:320px;"><input type="password" id="pin-input" placeholder="PIN" style="width:100%; padding:12px; font-size:1.2rem; text-align:center; border:1px solid var(--border); border-radius:8px; margin-bottom:15px;"><button class="btn btn-primary" style="width:100%; padding:12px; font-size:1rem;" onclick="App.logic.verificarPIN(document.getElementById('pin-input').value)">Entrar</button></div></div>`; };

App.views.inicio = function() { 
    document.getElementById('bottom-nav').style.display = 'flex'; 
    const pedidosCount = App.state.pedidos ? App.state.pedidos.length : 0; 
    const prodCount = App.state.ordenes_produccion ? App.state.ordenes_produccion.filter(o => o.estado !== 'listo').length : 0; 
    let alertasHTML = ''; 
    const stockBajo = App.state.inventario.filter(i => parseFloat(i.stock_minimo) > 0 && parseFloat(i.stock_actual) <= parseFloat(i.stock_minimo)); 
    if(stockBajo.length > 0) { alertasHTML += `<div style="background:#FED7D7; border-left:4px solid #E53E3E; padding:10px; margin-bottom:15px; border-radius:4px;"><strong style="color:#E53E3E;">⚠️ Alerta de Stock Bajo:</strong><ul style="margin:5px 0 0 20px; color:#C53030; font-size:0.85rem;">`; stockBajo.forEach(i => { alertasHTML += `<li>${App.ui.escapeHTML(i.nombre)}: Quedan ${i.stock_actual} ${App.ui.escapeHTML(i.unidad)} (Mínimo: ${i.stock_minimo})</li>`; }); alertasHTML += `</ul></div>`; } 
    
    let pedAtrasados = 0; let pedUrgentes = 0; const hoy = new Date(); hoy.setHours(0,0,0,0);
    App.state.pedidos.forEach(p => {
        if(p.estado !== 'listo para entregar' && p.estado !== 'pagado' && p.fecha_entrega) {
            const fEnt = new Date(p.fecha_entrega+'T00:00:00'); const diffDias = Math.ceil((fEnt - hoy)/(1000*60*60*24));
            if(diffDias < 0) pedAtrasados++; else if(diffDias >= 0 && diffDias <= 3) pedUrgentes++;
        }
    });
    
    if(pedAtrasados > 0 || pedUrgentes > 0) {
        alertasHTML += `<div style="background:#FFF5F5; border-left:4px solid var(--danger); padding:10px; margin-bottom:15px; border-radius:4px;"><strong style="color:var(--danger);">🚨 Alerta de Entregas:</strong><ul style="margin:5px 0 0 20px; color:var(--danger); font-size:0.85rem;">`;
        if(pedAtrasados > 0) alertasHTML += `<li>¡Tienes <strong>${pedAtrasados} pedido(s) atrasado(s)</strong>!</li>`;
        if(pedUrgentes > 0) alertasHTML += `<li>Hay ${pedUrgentes} pedido(s) a entregar pronto.</li>`;
        alertasHTML += `</ul></div>`;
    }
    return `${alertasHTML}<div class="grid-2"><div class="card stat-card"><div class="label">Pedidos</div><div class="value">${pedidosCount}</div></div><div class="card stat-card"><div class="label">Producción</div><div class="value">${prodCount}</div></div><div class="card stat-card" onclick="App.router.navigate('nomina')" style="cursor:pointer; background:#FFF5F5;"><div class="label" style="color:#E53E3E;">Nómina</div><div class="value">🧑‍🎨</div></div><div class="card stat-card" onclick="App.router.navigate('finanzas')" style="cursor:pointer; background:#EBF8FF;"><div class="label" style="color:#3182CE;">Ver Finanzas</div><div class="value">📊</div></div></div>`; 
};

App.views.inventario = function() { 
    document.getElementById('bottom-nav').style.display = 'flex'; 
    let html = `<div class="card"><div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:15px;"><h3 class="card-title" style="margin:0;">Bodega (Inventario Inteligente)</h3><button class="btn btn-secondary" style="padding:6px 10px; font-size:0.8rem; border-color:var(--primary); color:var(--primary); background:transparent;" onclick="App.views.modalEstadisticas()">📊 Reportes</button></div><button class="btn btn-secondary" style="width:100%; margin-bottom:15px; border-color:#38A169; color:#38A169; background:transparent;" onclick="window.exportarAExcel(App.state.inventario, 'Inventario_DescansoMaya')">📥 Descargar Tabla en Excel</button><input type="text" id="bus-inv" onkeyup="window.filtrarLista('bus-inv', 'fila-inv')" placeholder="🔍 Buscar insumo..." style="width:100%; padding:8px; margin-bottom:15px; border-radius:6px; border:1px solid var(--border);">`; 
    if (!App.state.inventario || App.state.inventario.length === 0) { html += `<p>No hay insumos.</p>`; } 
    else { 
        html += `<table style="width:100%; border-collapse: collapse; font-size: 0.85rem;"><tr style="border-bottom: 2px solid var(--border);"><th style="text-align:left; padding:8px;">Artículo</th><th style="padding:8px; text-align:center;">Físico</th><th style="padding:8px; text-align:center;">Apartado</th><th style="padding:8px; text-align:center; color:var(--primary);">Libre</th><th></th></tr>`; 
        App.state.inventario.forEach(i => { 
            const real = parseFloat(i.stock_real||0);
            const reservado = parseFloat(i.stock_reservado||0);
            const comprometido = parseFloat(i.stock_comprometido||0);
            const libre = real - reservado - comprometido;
            const colorLibre = (parseFloat(i.stock_minimo)>0 && libre <= parseFloat(i.stock_minimo)) ? 'var(--danger)' : 'var(--primary)';
            
            html += `<tr class="fila-inv" style="border-bottom: 1px solid var(--border);"><td style="padding: 10px 5px;"><strong>${App.ui.escapeHTML(i.nombre)}</strong><br><small style="color:var(--text-muted); text-transform:uppercase; font-size:0.7rem;">[${App.ui.escapeHTML(i.tipo || 'OTRO')}]</small></td><td style="padding: 10px 5px; text-align:center; font-weight:bold; color:var(--text-main)">${real}</td><td style="padding: 10px 5px; text-align:center; color:#D69E2E">${reservado + comprometido}</td><td style="padding: 10px 5px; text-align:center; font-weight:bold; font-size:1.1rem; color:${colorLibre}">${libre}</td><td style="text-align:right;"><button class="btn btn-secondary" style="padding:4px; font-size:0.8rem; margin-right:4px;" onclick="App.views.modalKardex('${i.id}')">📋</button><button class="btn btn-secondary" style="padding:4px; font-size:0.8rem;" onclick="App.views.formMaterial('${i.id}')">✏️</button></td></tr>`; 
        }); 
        html += `</table>`; 
    } 
    html += `</div><button class="fab" onclick="App.views.formMaterial()">+</button>`; return html; 
};

App.views.modalEstadisticas = function() { const valorTotal = App.state.inventario.reduce((sum, item) => sum + (parseFloat(item.stock_actual||0) * parseFloat(item.costo_unitario||0)), 0); let consumos = {}; (App.state.movimientos_inventario||[]).forEach(m => { if(m.tipo_movimiento.includes('salida')) { consumos[m.ref_id] = (consumos[m.ref_id] || 0) + Math.abs(parseFloat(m.cantidad)); } }); let topMateriales = Object.entries(consumos).sort((a,b) => b[1] - a[1]).slice(0, 3); let topHtml = topMateriales.map(t => { let mat = App.state.inventario.find(m => m.id === t[0]); return `<li>${mat ? App.ui.escapeHTML(mat.nombre) : 'Desconocido'}: <strong>${t[1]}</strong> uds.</li>`; }).join(''); if(!topHtml) topHtml = "<li>Aún no hay datos de consumo.</li>"; let prodCount = {}; (App.state.pedido_detalle||[]).forEach(d => { prodCount[d.producto_id] = (prodCount[d.producto_id] || 0) + parseInt(d.cantidad||1); }); let topProd = Object.entries(prodCount).sort((a,b) => b[1] - a[1]).slice(0,3); let topProdHtml = topProd.map(t => { let p = App.state.productos.find(x => x.id === t[0]); return `<li>${p ? App.ui.escapeHTML(p.nombre) : 'Desconocido'}: <strong>${t[1]}</strong> pedidos</li>`; }).join(''); if(!topProdHtml) topProdHtml = "<li>Aún no hay pedidos.</li>"; let html = `<div class="grid-2" style="margin-bottom:15px;"><div class="card stat-card" style="background:#EBF8FF;"><div class="label" style="color:#2B6CB0;">Valor del Inventario</div><div class="value" style="color:#2B6CB0; font-size:1.2rem;">$${valorTotal.toFixed(2)}</div></div></div><div style="background:#F7FAFC; padding:10px; border-radius:8px; margin-bottom:10px; border:1px solid var(--border);"><strong style="color:var(--primary);">🧵 Top 3 Insumos más usados</strong><ul style="margin-top:5px; margin-left:20px; font-size:0.85rem;">${topHtml}</ul></div><div style="background:#F7FAFC; padding:10px; border-radius:8px; margin-bottom:15px; border:1px solid var(--border);"><strong style="color:var(--primary);">🏆 Top 3 Productos estrella</strong><ul style="margin-top:5px; margin-left:20px; font-size:0.85rem;">${topProdHtml}</ul></div><button class="btn btn-primary" style="width:100%;" onclick="App.ui.closeSheet()">Cerrar</button>`; App.ui.openSheet("Reporte de Producción", html); };
App.views.modalKardex = function(matId) { const material = App.state.inventario.find(m => m.id === matId); const movs = (App.state.movimientos_inventario || []).filter(m => m.ref_id === matId).reverse(); let html = `<div style="margin-bottom:15px; font-size:0.9rem;">Movimientos de <strong>${App.ui.escapeHTML(material.nombre)}</strong></div>`; html += `<table style="width:100%; font-size:0.8rem; border-collapse:collapse;"><tr style="border-bottom:1px solid #ccc;"><th style="text-align:left;">Fecha</th><th>Mov</th><th>Cant.</th><th>Notas</th></tr>`; if(movs.length===0) html += `<tr><td colspan="4" style="padding:10px;text-align:center;">Sin movimientos</td></tr>`; movs.forEach(m => { const color = parseFloat(m.cantidad) > 0 ? 'var(--success)' : 'var(--danger)'; const signo = parseFloat(m.cantidad) > 0 ? '+' : ''; html += `<tr style="border-bottom:1px dashed #eee;"><td style="padding:5px 0;">${m.fecha.split('T')[0]}</td><td><small>${App.ui.escapeHTML((m.tipo_movimiento||'').replace('_',' '))}</small></td><td style="text-align:center; font-weight:bold; color:${color};">${signo}${m.cantidad}</td><td><small>${App.ui.escapeHTML(m.notas||'')}</small></td></tr>`; }); html += `</table><button class="btn btn-primary" style="width:100%; margin-top:15px;" onclick="App.ui.closeSheet()">Cerrar</button>`; App.ui.openSheet(`Kardex (Auditoría)`, html); };
App.views.productos = function() { document.getElementById('bottom-nav').style.display = 'flex'; let html = `<div class="card"><h3 class="card-title">Catálogo de Productos</h3><input type="text" id="bus-prod" onkeyup="window.filtrarLista('bus-prod', 'tarj-prod')" placeholder="🔍 Buscar producto..." style="width:100%; padding:8px; margin-bottom:15px; border-radius:6px; border:1px solid var(--border);">`; if (!App.state.productos || App.state.productos.length === 0) { html += `<p style="color: var(--text-muted);">No hay productos registrados.</p>`; } else { App.state.productos.forEach(p => { html += `<div class="card tarj-prod" style="border: 1px solid var(--border); box-shadow: none; padding: 12px; display:flex; justify-content:space-between; align-items:center;"><div style="flex:1;"><strong>${App.ui.escapeHTML(p.nombre)}</strong><br><small style="color: var(--text-muted);">Cat: ${App.ui.escapeHTML(p.categoria || 'General')} | Clasif: ${App.ui.escapeHTML(p.clasificacion || 'Normal')}<br>Tamaño: ${App.ui.escapeHTML(p.tamano || '-')} | Color: ${App.ui.escapeHTML(p.color || '-')}</small></div><div style="text-align:right;"><span style="color: var(--primary); font-weight: bold; display:block; margin-bottom:5px;">$${p.precio_venta} <br><small style="color:var(--text-muted);">Mayoreo: $${p.precio_mayoreo||'N/A'}</small></span><div><button class="btn btn-secondary" style="padding:4px 8px; font-size:0.8rem; margin-right:4px;" onclick="App.views.formProducto('${p.id}')">✏️</button><button class="btn btn-secondary" style="padding:4px 8px; font-size:0.8rem; color:red; border-color:red;" onclick="App.logic.eliminarRegistroGenerico('productos', '${p.id}', 'productos')">🗑️</button></div></div></div>`; }); } html += `</div><button class="fab" onclick="App.views.formProducto()">+</button>`; return html; };

App.views.pedidos = function() { 
    document.getElementById('bottom-nav').style.display = 'flex'; 
    const pedNuevos = []; const pedTaller = []; const pedListos = []; const pedPagados = [];
    [...(App.state.pedidos||[])].reverse().slice(0, 100).forEach(p => { 
        const detalle = App.state.pedido_detalle.find(d => d.pedido_id === p.id); 
        const tieneOrden = detalle ? App.state.ordenes_produccion.some(o => o.pedido_detalle_id === detalle.id) : false; 
        const abonos = App.state.abonos.filter(a => a.pedido_id === p.id).reduce((sum, a) => sum + parseFloat(a.monto || 0), 0); 
        const saldoReal = parseFloat(p.total || 0) - parseFloat(p.anticipo || 0) - abonos; 
        let estadoCalculado = p.estado || 'nuevo'; 
        if (tieneOrden && estadoCalculado !== 'listo para entregar' && estadoCalculado !== 'pagado') estadoCalculado = 'en taller'; 
        if (saldoReal <= 0) estadoCalculado = 'pagado'; 
        p._objDetalle = detalle; p._tieneOrden = tieneOrden; p._saldoReal = saldoReal; p._estadoCalculado = estadoCalculado;
        if (estadoCalculado === 'pagado') pedPagados.push(p); else if (estadoCalculado === 'listo para entregar') pedListos.push(p); else if (estadoCalculado === 'en taller') pedTaller.push(p); else pedNuevos.push(p);
    }); 

    const dibujarTarjetaPed = (p) => {
        const c = App.state.clientes.find(cli => cli.id === p.cliente_id); const nombreC = p.cliente_id === "STOCK_INTERNO" ? "📦 BODEGA (Stock)" : (c ? App.ui.escapeHTML(c.nombre) : 'Mostrador'); 
        const producto = p._objDetalle ? App.state.productos.find(prod => prod.id === p._objDetalle.producto_id) : null; const estaPagado = p._saldoReal <= 0;
        let esUrgente = false; if(p.fecha_entrega && !estaPagado && p._estadoCalculado !== 'listo para entregar') { const fEnt = new Date(p.fecha_entrega+'T00:00:00'); const hoy = new Date(); hoy.setHours(0,0,0,0); if(Math.ceil((fEnt - hoy)/(1000*60*60*24)) <= 7) esUrgente = true; } 
        let botonesAccion = '';
        if (!p._tieneOrden && p._estadoCalculado === 'nuevo') { if (producto && producto.categoria === 'reventa') { botonesAccion = `<button class="btn btn-secondary" style="padding: 6px 10px; border-color:#3182CE; color:#3182CE;" onclick="App.logic.entregarDeBodega('${p.id}')">📦 Sacar de Bodega</button>`; } else { botonesAccion = `<button class="btn btn-secondary" style="padding: 6px 10px; border-color:var(--secondary); color:var(--secondary);" onclick="App.views.formMandarProduccion('${p.id}')">🔨 Mandar a taller</button><button class="btn btn-secondary" style="padding: 6px 10px; border-color:#3182CE; color:#3182CE; margin-left:5px;" onclick="App.logic.entregarDeBodega('${p.id}')">📦 Bodega</button>`; } }
        return `<div class="card tarj-ped" data-estado="${p._estadoCalculado}" style="border: ${esUrgente ? '2px solid var(--danger)' : '1px solid var(--border)'}; box-shadow: none; margin-bottom: 10px;"><div style="display: flex; justify-content: space-between; margin-bottom: 8px;"><strong>${(p.id||'').replace('PED-','')} - ${nombreC}</strong>${estaPagado ? `<span class="badge" style="background: var(--success); color: white;">PAGADO</span>` : `<span class="badge ${p._estadoCalculado || 'nuevo'}">${String(p._estadoCalculado || 'Nuevo').toUpperCase()}</span>`}</div><p style="color: var(--primary); font-size: 0.9rem; font-weight: bold; margin-bottom: 5px;">${producto ? App.ui.escapeHTML(producto.nombre) : 'Desconocido'}</p><div style="display: flex; justify-content: space-between; align-items: center; margin-top: 10px; padding-top: 10px; border-top: 1px dashed var(--border);"><div><strong style="color: ${estaPagado ? 'var(--success)' : 'var(--danger)'};">Saldo: $${p._saldoReal > 0 ? p._saldoReal : 0}</strong></div><div style="display: flex; gap: 8px;">${botonesAccion}${!estaPagado && p.cliente_id !== "STOCK_INTERNO" ? `<button class="btn btn-primary" style="padding: 6px 10px; background: var(--success); border-color: var(--success);" onclick="App.views.formCobrar('${p.id}', '${c ? c.id : ''}', ${p._saldoReal})">💰</button>` : ''}</div></div><div style="display: flex; gap: 10px; margin-top: 15px;">${p.cliente_id !== "STOCK_INTERNO" ? `<button class="btn" style="flex: 1; font-size: 0.8rem; border-color: #38A169; color: #38A169;" onclick="App.views.modalOpcionesWhatsApp('${p.id}')">💬 WApp</button><button class="btn" style="flex: 1; font-size: 0.8rem; border-color: var(--primary); color: var(--primary);" onclick="App.logic.imprimirNota('${p.id}')">🖨️ PDF</button>` : ''}<button class="btn btn-secondary" style="font-size: 0.8rem; padding: 6px 10px;" onclick="App.views.formEditarPedido('${p.id}')">✏️</button><button class="btn btn-secondary" style="font-size: 0.8rem; padding: 6px 10px; color: red; border-color: red;" onclick="App.logic.eliminarPedido('${p.id}')">🗑️</button></div></div>`;
    };

    let html = `<div class="card"><h3 class="card-title">Gestión de Pedidos</h3><input type="text" id="bus-ped" onkeyup="window.filtrarLista('bus-ped', 'tarj-ped')" placeholder="🔍 Buscar por folio o producto..." style="width:100%; padding:8px; margin-bottom:15px; border-radius:6px; border:1px solid var(--border);"><div style="display: flex; margin-bottom: 15px; background: white; border-radius: 8px; overflow: hidden; border: 1px solid var(--border); overflow-x: auto;"><button class="tab-btn-ped" style="flex:1; min-width:80px; padding: 12px 5px; border:none; background:#F3F0FF; color:var(--primary); font-weight:bold; font-size:0.85rem; border-bottom: 2px solid var(--primary);" onclick="window.switchTabPed('nuevos', this)">Nuevos (${pedNuevos.length})</button><button class="tab-btn-ped" style="flex:1; min-width:80px; padding: 12px 5px; border:none; background:transparent; color:var(--text-muted); font-weight:bold; font-size:0.85rem; border-bottom: 2px solid transparent;" onclick="window.switchTabPed('taller', this)">Taller (${pedTaller.length})</button><button class="tab-btn-ped" style="flex:1; min-width:80px; padding: 12px 5px; border:none; background:transparent; color:var(--text-muted); font-weight:bold; font-size:0.85rem; border-bottom: 2px solid transparent;" onclick="window.switchTabPed('listos', this)">Listos (${pedListos.length})</button><button class="tab-btn-ped" style="flex:1; min-width:80px; padding: 12px 5px; border:none; background:transparent; color:var(--text-muted); font-weight:bold; font-size:0.85rem; border-bottom: 2px solid transparent;" onclick="window.switchTabPed('pagados', this)">Pagados</button></div><div id="tab-nuevos" class="tab-content-ped" style="display:block;">${pedNuevos.length === 0 ? '<div class="card" style="text-align:center; color:var(--text-muted); padding:30px;">Sin pedidos nuevos.</div>' : pedNuevos.map(dibujarTarjetaPed).join('')}</div><div id="tab-taller" class="tab-content-ped" style="display:none;">${pedTaller.length === 0 ? '<div class="card" style="text-align:center; color:var(--text-muted); padding:30px;">No hay pedidos en taller.</div>' : pedTaller.map(dibujarTarjetaPed).join('')}</div><div id="tab-listos" class="tab-content-ped" style="display:none;">${pedListos.length === 0 ? '<div class="card" style="text-align:center; color:var(--text-muted); padding:30px;">No hay pedidos listos esperando pago.</div>' : pedListos.map(dibujarTarjetaPed).join('')}</div><div id="tab-pagados" class="tab-content-ped" style="display:none;">${pedPagados.length === 0 ? '<div class="card" style="text-align:center; color:var(--text-muted); padding:30px;">Historial vacío.</div>' : pedPagados.map(dibujarTarjetaPed).join('')}</div>`; return html += `</div><button class="fab" onclick="App.views.formNuevoPedido()">+</button>`; 
};

App.views.modalOpcionesWhatsApp = function(pedidoId) { let html = `<div style="display:flex; flex-direction:column; gap:10px;"><p style="font-size:0.85rem; color:var(--text-muted); margin-bottom:10px;">Elige el tipo de mensaje que deseas enviar al cliente:</p><button class="btn btn-secondary" style="border-color:#38A169; color:#38A169; background:transparent;" onclick="App.logic.enviarWhatsApp('${pedidoId}', 'listo')">✅ Aviso de "Pedido Listo"</button><button class="btn btn-secondary" style="border-color:#D69E2E; color:#D69E2E; background:transparent;" onclick="App.logic.enviarWhatsApp('${pedidoId}', 'cobro')">💰 Recordatorio de Pago</button><button class="btn btn-secondary" style="border-color:var(--primary); color:var(--primary); background:transparent;" onclick="App.logic.enviarWhatsApp('${pedidoId}', 'general')">📝 Detalles del Pedido (General)</button></div>`; App.ui.openSheet("Enviar WhatsApp", html); };

App.views.produccion = function() { 
    document.getElementById('bottom-nav').style.display = 'flex'; 
    const pendientes = (App.state.ordenes_produccion||[]).filter(o => o.estado === 'pendiente' || !o.estado); const enProceso = (App.state.ordenes_produccion||[]).filter(o => o.estado === 'en_proceso'); const listas = (App.state.ordenes_produccion||[]).filter(o => o.estado === 'listo'); 
    const dibujarTarjeta = (orden) => { 
        const detalle = App.state.pedido_detalle.find(d => d.id === orden.pedido_detalle_id) || App.state.pedido_detalle.find(d => d.pedido_id === orden.pedido_detalle_id) || {}; const producto = detalle.producto_id ? App.state.productos.find(p => p.id === detalle.producto_id) : null; const pedido = App.state.pedidos.find(p => p.id === detalle.pedido_id) || {}; 
        let nombreCliente = 'Sin Cliente'; if(pedido.cliente_id === "STOCK_INTERNO") { nombreCliente = "📦 BODEGA"; } else if (pedido.cliente_id) { const clienteObj = App.state.clientes.find(c => c.id === pedido.cliente_id); if(clienteObj) nombreCliente = App.ui.escapeHTML(clienteObj.nombre); } 
        const pagos = App.state.pago_artesanos.filter(p => p.orden_id === orden.id); let infoArtesanos = pagos.length > 0 ? `🛠️ ${pagos.length} Trabajos` : '👤 Sin asignar'; let semaforo = ''; 
        if(pedido.fecha_entrega && orden.estado !== 'listo') { const fEnt = new Date(pedido.fecha_entrega+'T00:00:00'); const hoy = new Date(); hoy.setHours(0,0,0,0); const d = Math.ceil((fEnt - hoy)/(1000*60*60*24)); if(d < 0) semaforo = '<span style="background:red; color:white; padding:2px 6px; border-radius:4px; font-size:0.7rem; margin-left:5px;">🔴 Atrasado</span>'; else if(d <= 1) semaforo = '<span style="background:orange; color:white; padding:2px 6px; border-radius:4px; font-size:0.7rem; margin-left:5px;">🟡 Urgente</span>'; else semaforo = '<span style="background:green; color:white; padding:2px 6px; border-radius:4px; font-size:0.7rem; margin-left:5px;">🟢 A tiempo</span>'; } 
        return `<div class="card" style="border: 1px solid var(--border); box-shadow: none; cursor: pointer; margin-bottom: 10px;" onclick="App.views.modalEditarOrden('${orden.id}')"><div style="display:flex; justify-content:space-between; margin-bottom:5px;"><strong>${orden.id}</strong><div><span style="font-size:0.75rem; color:#718096; font-weight:bold;">${pedido.id ? pedido.id.replace('PED-','') : 'Huérfana'}</span>${semaforo}</div></div><small style="color: var(--primary); font-weight: 600; display:block; font-size:1rem; margin-bottom:2px;">${producto ? App.ui.escapeHTML(producto.nombre) : 'Producto interno'}</small><small style="color: #4A5568; display:block; margin-bottom:5px; font-weight:bold;">👤 ${nombreCliente}</small><div style="margin-top: 8px; font-size: 0.85rem; color: var(--text-muted); display:flex; justify-content: space-between; border-top: 1px dashed #E2E8F0; padding-top: 8px;"><span>${infoArtesanos}</span><span style="color:var(--primary);">Ver detalles ➔</span></div></div>`; 
    }; 
    let html = `<div class="card"><h3 class="card-title">Taller de Producción</h3><button class="btn btn-secondary" style="width:100%; margin-top:5px; border: 2px dashed var(--primary); color: var(--primary); background: transparent; font-weight: bold;" onclick="App.views.formOrdenStock()">+ 🔨 Fabricar para Bodega</button></div><div style="display: flex; margin-bottom: 15px; background: white; border-radius: 8px; overflow: hidden; border: 1px solid var(--border);"><button class="tab-btn-prod" style="flex:1; padding: 12px 5px; border:none; background:#F3F0FF; color:var(--primary); font-weight:bold; font-size:0.85rem; border-bottom: 2px solid var(--primary);" onclick="window.switchTabProd('pendientes', this)">🕒 Pendientes (${pendientes.length})</button><button class="tab-btn-prod" style="flex:1; padding: 12px 5px; border:none; background:transparent; color:var(--text-muted); font-weight:bold; font-size:0.85rem; border-bottom: 2px solid transparent;" onclick="window.switchTabProd('en_proceso', this)">🏃 En Proceso (${enProceso.length})</button><button class="tab-btn-prod" style="flex:1; padding: 12px 5px; border:none; background:transparent; color:var(--text-muted); font-weight:bold; font-size:0.85rem; border-bottom: 2px solid transparent;" onclick="window.switchTabProd('listas', this)">✅ Listas (${listas.length})</button></div><div id="tab-pendientes" class="tab-content-prod" style="display:block;">${pendientes.length === 0 ? '<div class="card" style="text-align:center; color:var(--text-muted); padding:30px;">No hay órdenes pendientes.</div>' : pendientes.map(dibujarTarjeta).join('')}</div><div id="tab-en_proceso" class="tab-content-prod" style="display:none;">${enProceso.length === 0 ? '<div class="card" style="text-align:center; color:var(--text-muted); padding:30px;">Nadie está tejiendo hamacas.</div>' : enProceso.map(dibujarTarjeta).join('')}</div><div id="tab-listas" class="tab-content-prod" style="display:none;">${listas.length === 0 ? '<div class="card" style="text-align:center; color:var(--text-muted); padding:30px;">No hay hamacas listas esperando cierre.</div>' : listas.map(dibujarTarjeta).join('')}</div>`; return html; 
};

App.views.nomina = function() { document.getElementById('bottom-nav').style.display = 'flex'; let html = `<div class="card"><h3 class="card-title">Nómina de Artesanos</h3>`; const pagosPorArtesano = {}; App.state.artesanos.forEach(a => { pagosPorArtesano[a.id] = { nombre: a.nombre, totalPendiente: 0, trabajos: [] }; }); App.state.pago_artesanos.forEach(p => { if (p.estado === 'pendiente' && pagosPorArtesano[p.artesano_id]) { pagosPorArtesano[p.artesano_id].totalPendiente += parseFloat(p.total); pagosPorArtesano[p.artesano_id].trabajos.push(p); } }); let hayPendientes = false; for (const [id, data] of Object.entries(pagosPorArtesano)) { if (data.totalPendiente > 0) { hayPendientes = true; html += `<div class="card" style="border: 1px solid var(--border); box-shadow: none;"><div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 10px;"><strong>🧑‍🎨 ${App.ui.escapeHTML(data.nombre)}</strong><strong style="color: var(--danger); font-size: 1.1rem;">$${data.totalPendiente}</strong></div><div style="display: flex; gap: 10px;"><button class="btn btn-secondary" style="flex: 1; border-color: var(--primary); color: var(--primary); background: transparent;" onclick="App.views.detalleNominaArtesano('${id}')">📋 Ver Detalles</button><button class="btn btn-primary" style="flex: 1; background: var(--success); border-color: var(--success);" onclick="if(confirm('¿Liquidar $${data.totalPendiente} a ${App.ui.escapeHTML(data.nombre)}?')) App.logic.liquidarNomina('${id}')">💵 Liquidar</button></div></div>`; } } if (!hayPendientes) html += `<p style="color: var(--text-muted);">No hay pagos pendientes. Todo está al día. ✨</p>`; html += `</div>`; return html; };
App.views.detalleNominaArtesano = function(artesanoId) { const artesano = App.state.artesanos.find(a => a.id === artesanoId); const pagosPendientes = App.state.pago_artesanos.filter(p => p.artesano_id === artesanoId && p.estado === 'pendiente'); let html = `<div style="margin-bottom:15px;"><p style="color:var(--text-muted); font-size:0.85rem;">Trabajos sin pagar de <strong>${App.ui.escapeHTML(artesano.nombre)}</strong>:</p><ul style="list-style:none; padding:0; margin:0;">`; pagosPendientes.forEach(p => { const orden = App.state.ordenes_produccion.find(o => o.id === p.orden_id); let nombreProducto = 'Orden ' + p.orden_id.replace('ORD-',''); if(orden) { const detalle = App.state.pedido_detalle.find(d => d.id === orden.pedido_detalle_id); if(detalle) { const prod = App.state.productos.find(pr => pr.id === detalle.producto_id); if(prod) nombreProducto = App.ui.escapeHTML(prod.nombre); } } const partesID = p.id.split('-'); const nombreTarea = partesID.length > 2 ? partesID.slice(2).join(' ') : 'Trabajo general'; html += `<li style="padding:10px 0; border-bottom:1px dashed #ccc; display:flex; justify-content:space-between; align-items:center;"><div><strong>${App.ui.escapeHTML(nombreTarea)}</strong><br><small style="color:var(--text-muted);">${nombreProducto}</small><br><small style="color:var(--text-muted);">${p.fecha.split('T')[0]}</small></div><div style="text-align:right;"><span style="color:var(--danger); font-weight:bold; display:block; margin-bottom:5px;">$${p.total}</span><button class="btn btn-secondary" style="padding:2px 6px; font-size:0.7rem; color:red; border-color:red;" onclick="App.ui.closeSheet(); App.logic.eliminarRegistroGenerico('pago_artesanos', '${p.id}', 'pago_artesanos')">🗑️ Cancelar</button></div></li>`; }); html += `</ul><button class="btn btn-primary" style="width:100%; margin-top:15px;" onclick="App.ui.closeSheet()">Cerrar</button></div>`; App.ui.openSheet(`Detalle de Nómina`, html); };
App.views.finanzas = function() { document.getElementById('bottom-nav').style.display = 'flex'; setTimeout(() => App.logic.renderGraficasFinanzas('todo'), 50); return `<div class="card"><div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:15px;"><h3 class="card-title" style="margin:0;">Finanzas</h3><select id="filtro-finanzas" onchange="App.logic.renderGraficasFinanzas(this.value)" style="padding:5px; border-radius:5px; border:1px solid #CBD5E0;"><option value="todo">Historial</option><option value="mes_actual">Este Mes</option><option value="mes_pasado">Mes Pasado</option><option value="trimestre_actual">Este Trimestre</option><option value="anio_actual">Este Año</option></select></div><div id="finanzas-contenedor">Cargando datos...</div></div><button class="fab" style="background: var(--danger);" onclick="App.views.formGasto()">+</button>`; };

App.views.detalleFinanzas = function(tipo, filtro) { 
    const hoy = new Date(); let mesActual = hoy.getMonth(); let anioActual = hoy.getFullYear(); let mesPasado = mesActual - 1; let anioPasado = anioActual; if(mesPasado < 0) { mesPasado = 11; anioPasado--; } let triActual = Math.floor(mesActual / 3); 
    const filtrarFecha = (str) => { if(filtro === 'todo') return true; if(!str) return false; const f = new Date(str); if(isNaN(f.getTime())) return false; if(filtro === 'mes_actual') return f.getMonth() === mesActual && f.getFullYear() === anioActual; if(filtro === 'mes_pasado') return f.getMonth() === mesPasado && f.getFullYear() === anioPasado; if(filtro === 'trimestre_actual') return Math.floor(f.getMonth() / 3) === triActual && f.getFullYear() === anioActual; if(filtro === 'anio_actual') return f.getFullYear() === anioActual; return true; }; 
    const pedFiltrados = (App.state.pedidos || []).filter(p => filtrarFecha(p.fecha_creacion)); const aboFiltrados = (App.state.abonos || []).filter(a => filtrarFecha(a.fecha)); const gasFiltrados = (App.state.gastos || []).filter(g => filtrarFecha(g.fecha)); const repFiltradas = (App.state.reparaciones || []).filter(r => filtrarFecha(r.fecha_creacion));
    
    // Función de ayuda para etiquetar si es Stock o Pedido normal
    const getEtiqueta = (clienteId) => clienteId === 'STOCK_INTERNO' ? '<span style="color:#D69E2E;">(Bodega)</span>' : '<span style="color:#3182CE;">(Pedido)</span>';

    let html = '<ul style="list-style:none; padding:0; margin:0;">'; 
    if (tipo === 'ventas') { 
        if(pedFiltrados.length===0 && repFiltradas.length===0) html += '<li>No hay ventas ni reparaciones registradas.</li>'; 
        pedFiltrados.forEach(p => { 
            const fecha = p.fecha_creacion ? String(p.fecha_creacion).split('T')[0] : '';
            html += `<li style="padding:8px 0; border-bottom:1px dashed #ccc; display:flex; justify-content:space-between;"><span><strong>${(p.id||'').replace('PED-','')} ${getEtiqueta(p.cliente_id)}</strong><br><small>${fecha}</small></span><span style="color:var(--primary); font-weight:bold;">$${parseFloat(p.total||0).toFixed(2)}</span></li>`; 
        }); 
        repFiltradas.forEach(r => { 
            const fecha = r.fecha_creacion ? String(r.fecha_creacion).split('T')[0] : '';
            html += `<li style="padding:8px 0; border-bottom:1px dashed #ccc; display:flex; justify-content:space-between;"><span><strong>${(r.id||'').replace('REP-','')} <span style="color:#805AD5;">(Rep)</span></strong><br><small>${fecha}</small></span><span style="color:var(--primary); font-weight:bold;">$${parseFloat(r.precio||0).toFixed(2)}</span></li>`; 
        }); 
    } else if (tipo === 'ingresos') { 
        const ants = pedFiltrados.filter(p => parseFloat(p.anticipo||0)>0); const antsRep = repFiltradas.filter(r => parseFloat(r.anticipo||0)>0);
        if(ants.length===0 && aboFiltrados.length===0 && antsRep.length===0) html += '<li>No hay ingresos.</li>'; 
        ants.forEach(p => { 
            const fecha = p.fecha_creacion ? String(p.fecha_creacion).split('T')[0] : '';
            html += `<li style="padding:8px 0; border-bottom:1px dashed #ccc; display:flex; justify-content:space-between;"><span><strong>Anticipo ${(p.id||'').replace('PED-','')} ${getEtiqueta(p.cliente_id)}</strong><br><small>${fecha}</small></span><span style="color:var(--success); font-weight:bold;">$${parseFloat(p.anticipo||0).toFixed(2)}</span></li>`; 
        }); 
        antsRep.forEach(r => { 
            const fecha = r.fecha_creacion ? String(r.fecha_creacion).split('T')[0] : '';
            html += `<li style="padding:8px 0; border-bottom:1px dashed #ccc; display:flex; justify-content:space-between;"><span><strong>Pago ${(r.id||'').replace('REP-','')} <span style="color:#805AD5;">(Rep)</span></strong><br><small>${fecha}</small></span><span style="color:var(--success); font-weight:bold;">$${parseFloat(r.anticipo||0).toFixed(2)}</span></li>`; 
        }); 
        aboFiltrados.forEach(a => { 
            const fecha = a.fecha ? String(a.fecha).split('T')[0] : '';
            const p = (App.state.pedidos || []).find(x => x.id === a.pedido_id) || {};
            html += `<li style="padding:8px 0; border-bottom:1px dashed #ccc; display:flex; justify-content:space-between;"><span><strong>Abono a ${(a.pedido_id||'').replace('PED-','')} ${getEtiqueta(p.cliente_id)}</strong><br><small>${fecha}</small></span><span style="color:var(--success); font-weight:bold;">$${parseFloat(a.monto||0).toFixed(2)}</span></li>`; 
        }); 
    } else if (tipo === 'gastos') { 
        if(gasFiltrados.length===0) html += '<li>No hay gastos registrados.</li>'; 
        gasFiltrados.forEach(g => { 
            const fecha = g.fecha ? String(g.fecha).split('T')[0] : '';
            html += `<li style="padding:8px 0; border-bottom:1px dashed #ccc; display:flex; justify-content:space-between; align-items:center;"><span><strong>${App.ui.escapeHTML(g.descripcion || '')}</strong><br><small>${fecha}</small></span><div style="text-align:right;"><span style="color:var(--danger); font-weight:bold; display:block; margin-bottom:5px;">$${parseFloat(g.monto||0).toFixed(2)}</span><button class="btn btn-secondary" style="padding:2px 6px; font-size:0.7rem; margin-right:4px;" onclick="App.ui.closeSheet(); setTimeout(()=>App.views.formGasto('${g.id}'), 300)">✏️</button><button class="btn btn-secondary" style="padding:2px 6px; font-size:0.7rem; color:red; border-color:red;" onclick="App.ui.closeSheet(); App.logic.eliminarRegistroGenerico('gastos', '${g.id}', 'gastos')">🗑️</button></div></li>`; 
        }); 
    } else if (tipo === 'por_cobrar') { 
        let hayCobros = false; 
        (App.state.pedidos || []).forEach(p => { 
            const abonos = (App.state.abonos || []).filter(a => a.pedido_id === p.id).reduce((s,a)=>s+parseFloat(a.monto||0),0); 
            const saldo = parseFloat(p.total||0) - parseFloat(p.anticipo||0) - abonos; 
            if(saldo > 0) { 
                hayCobros=true; 
                const fecha = p.fecha_creacion ? String(p.fecha_creacion).split('T')[0] : '';
                html += `<li style="padding:8px 0; border-bottom:1px dashed #ccc; display:flex; justify-content:space-between;"><span><strong>${(p.id||'').replace('PED-','')} ${getEtiqueta(p.cliente_id)}</strong><br><small>${fecha}</small></span><span style="color:#D69E2E; font-weight:bold;">$${saldo.toFixed(2)}</span></li>`; 
            } 
        }); 
        (App.state.reparaciones || []).forEach(r => { 
            const saldo = parseFloat(r.precio||0) - parseFloat(r.anticipo||0); 
            if(saldo > 0) { 
                hayCobros=true; 
                const fecha = r.fecha_creacion ? String(r.fecha_creacion).split('T')[0] : '';
                html += `<li style="padding:8px 0; border-bottom:1px dashed #ccc; display:flex; justify-content:space-between;"><span><strong>${(r.id||'').replace('REP-','')} <span style="color:#805AD5;">(Rep)</span></strong><br><small>${fecha}</small></span><span style="color:#D69E2E; font-weight:bold;">$${saldo.toFixed(2)}</span></li>`; 
            } 
        });
        if(!hayCobros) html += '<li>No hay saldo pendiente.</li>'; 
    } else if (tipo === 'por_pagar') { 
        let hayDeudas = false; 
        (App.state.pago_artesanos || []).forEach(pa => { 
            if(pa.estado === 'pendiente') { 
                hayDeudas=true; 
                const a = (App.state.artesanos || []).find(x => x.id === pa.artesano_id); 
                const fecha = pa.fecha ? String(pa.fecha).split('T')[0] : '';
                html += `<li style="padding:8px 0; border-bottom:1px dashed #ccc; display:flex; justify-content:space-between;"><span><strong>${a?a.nombre:'Artesano'} (Nómina)</strong><br><small>${fecha}</small></span><span style="color:#E53E3E; font-weight:bold;">$${parseFloat(pa.total||0).toFixed(2)}</span></li>`; 
            } 
        }); 
        (App.state.compras || []).forEach(c => { 
            const deuda = parseFloat(c.total||0) - parseFloat(c.monto_pagado||c.total||0); 
            if(deuda > 0) { 
                hayDeudas=true; 
                const pv = (App.state.proveedores || []).find(x => x.id === c.proveedor_id); 
                const fecha = c.fecha ? String(c.fecha).split('T')[0] : '';
                html += `<li style="padding:8px 0; border-bottom:1px dashed #ccc; display:flex; justify-content:space-between;"><span><strong>${pv?pv.nombre:'Proveedor'} (Compra)</strong><br><small>${fecha}</small></span><span style="color:#E53E3E; font-weight:bold;">$${deuda.toFixed(2)}</span></li>`; 
            } 
        });
        if(!hayDeudas) html += '<li>No hay deudas por pagar. ¡Estás al día!</li>'; 
    }
    
    html += '</ul><button class="btn btn-primary" style="width:100%; margin-top:15px;" onclick="App.ui.closeSheet()">Cerrar</button>'; 
    App.ui.openSheet(tipo === 'ventas' ? "Detalle de Ventas" : tipo === 'ingresos' ? "Detalle de Ingresos" : tipo === 'gastos' ? "Detalle de Gastos" : tipo === 'por_pagar' ? "Saldos por Pagar" : "Saldos Históricos", html); 
};

App.views.mas = function() { return `<div class="grid-2"><div class="card stat-card" style="cursor:pointer;" onclick="App.router.navigate('clientes')"><div class="label" style="margin-top:0;">👥 Clientes</div></div><div class="card stat-card" style="cursor:pointer;" onclick="App.router.navigate('proveedores')"><div class="label" style="margin-top:0;">🚚 Proveedores</div></div><div class="card stat-card" style="cursor:pointer;" onclick="App.router.navigate('artesanos')"><div class="label" style="margin-top:0;">🧑‍🎨 Artesanos / Tareas</div></div><div class="card stat-card" style="cursor:pointer; background: #F0FFF4;" onclick="App.router.navigate('inventario')"><div class="label" style="margin-top:0; color:#276749;">📦 Bodega / Insumos</div></div><div class="card stat-card" style="cursor:pointer;" onclick="App.router.navigate('productos')"><div class="label" style="margin-top:0;">🧶 Productos / Recetas</div></div><div class="card stat-card" style="cursor:pointer; background: #EBF8FF;" onclick="App.router.navigate('compras')"><div class="label" style="margin-top:0; color:#3182CE;">🛒 Ingresar Compra</div></div><div class="card stat-card" style="cursor:pointer; background: #FAF5FF;" onclick="App.router.navigate('reparaciones')"><div class="label" style="margin-top:0; color:#6B46C1;">🪡 Reparaciones</div></div><div class="card stat-card" style="cursor:pointer; background: #EEF2FF;" onclick="App.router.navigate('cotizaciones')"><div class="label" style="margin-top:0; color:#4C51BF;">📝 Cotizaciones</div></div><div class="card stat-card" style="cursor:pointer; background: #EDF2F7; grid-column: span 2;" onclick="App.router.navigate('configuracion')"><div class="label" style="margin-top:0; color: #4A5568;">⚙️ Configuración</div></div></div>`; };

App.views.modalEstadoCuenta = function(clienteId) { 
    const cliente = (App.state.clientes || []).find(c => c.id === clienteId); if(!cliente) return;
    const pedCli = (App.state.pedidos || []).filter(p => p.cliente_id === clienteId); 
    const repCli = (App.state.reparaciones || []).filter(r => r.cliente_id === clienteId); // NUEVO: Traer reparaciones
    
    let totalComprado = 0; let saldoPendiente = 0; let listaPedidos = ''; 
    
    // Procesar Pedidos
    pedCli.forEach(p => { 
        totalComprado += parseFloat(p.total||0); 
        const abonos = (App.state.abonos || []).filter(a => a.pedido_id === p.id).reduce((s,a)=>s+parseFloat(a.monto||0),0); 
        const deuda = parseFloat(p.total||0) - parseFloat(p.anticipo||0) - abonos; 
        if(deuda > 0) saldoPendiente += deuda; 
        
        const detalle = (App.state.pedido_detalle || []).find(d => d.pedido_id === p.id); 
        const prod = detalle ? (App.state.productos || []).find(x => x.id === detalle.producto_id) : null; 
        const nombreProd = prod ? App.ui.escapeHTML(prod.nombre) : 'Artículo especial';
        const fecha = p.fecha_creacion ? String(p.fecha_creacion).split('T')[0] : '';
        
        listaPedidos += `<li style="padding:8px 0; border-bottom:1px dashed #ccc; display:flex; justify-content:space-between;"><span><strong>${(p.id || '').replace('PED-','')} (Pedido)</strong> - <small style="color:var(--primary); font-weight:bold;">${nombreProd}</small><br><small>${fecha}</small></span><span style="color:var(--primary); font-weight:bold;">$${parseFloat(p.total||0).toFixed(2)}</span></li>`; 
    }); 

    // Procesar Reparaciones (NUEVO)
    repCli.forEach(r => {
        totalComprado += parseFloat(r.precio||0);
        const deuda = parseFloat(r.precio||0) - parseFloat(r.anticipo||0);
        if(deuda > 0) saldoPendiente += deuda;

        const fecha = r.fecha_creacion ? String(r.fecha_creacion).split('T')[0] : '';
        listaPedidos += `<li style="padding:8px 0; border-bottom:1px dashed #ccc; display:flex; justify-content:space-between;"><span><strong>${(r.id || '').replace('REP-','')} (Reparación)</strong> - <small style="color:#805AD5; font-weight:bold;">${App.ui.escapeHTML(r.descripcion || 'Servicio')}</small><br><small>${fecha}</small></span><span style="color:var(--primary); font-weight:bold;">$${parseFloat(r.precio||0).toFixed(2)}</span></li>`; 
    });
    
    if(listaPedidos === '') listaPedidos = '<li style="padding:10px; color:var(--text-muted);">No tiene historial de compras ni reparaciones.</li>'; 
    
    let html = `<div class="grid-2" style="margin-bottom:15px;"><div class="card stat-card" style="background:#EBF8FF;"><div class="label" style="color:#2B6CB0;">Total Comprado</div><div class="value" style="color:#3182CE; font-size:1.2rem;">$${totalComprado.toFixed(2)}</div></div><div class="card stat-card" style="background:#FFF5F5;"><div class="label" style="color:#C53030;">Saldo Pendiente</div><div class="value" style="color:#E53E3E; font-size:1.2rem;">$${saldoPendiente.toFixed(2)}</div></div></div><h4 style="margin-bottom:10px; color:var(--text-main);">Historial del Cliente</h4><ul style="list-style:none; padding:0; margin:0; max-height:250px; overflow-y:auto; background:#f9f9f9; border-radius:8px; padding:10px; border:1px solid var(--border);">${listaPedidos}</ul><button class="btn btn-primary" style="width:100%; margin-top:15px;" onclick="App.ui.closeSheet()">Cerrar Perfil</button>`; 
    App.ui.openSheet(`👤 ${App.ui.escapeHTML(cliente.nombre)}`, html); 
};

App.views.clientes = function() { document.getElementById('bottom-nav').style.display = 'flex'; let html = `<div class="card"><h3 class="card-title">Directorio de Clientes</h3><button class="btn btn-secondary" style="width:100%; margin-bottom:15px; border-color:#38A169; color:#38A169; background:transparent;" onclick="window.exportarAExcel(App.state.clientes, 'Clientes_DescansoMaya')">📥 Descargar Tabla en Excel</button><input type="text" id="bus-cli" onkeyup="window.filtrarLista('bus-cli', 'tarj-cli')" placeholder="🔍 Buscar cliente..." style="width:100%; padding:8px; margin-bottom:15px; border-radius:6px; border:1px solid var(--border);">`; App.state.clientes.forEach(c => { html += `<div class="card tarj-cli" style="border: 1px solid var(--border); padding: 10px; margin-bottom: 8px; display:flex; justify-content:space-between; align-items:center;"><div><strong>${App.ui.escapeHTML(c.nombre)}</strong><br><small style="color: var(--text-muted);">📞 ${c.telefono || 'N/A'}</small></div><div><button class="btn btn-secondary" style="padding:4px 8px; font-size:0.8rem; margin-right:4px; border-color:var(--primary); color:var(--primary); background:transparent;" onclick="App.views.modalEstadoCuenta('${c.id}')">📋 Perfil y Compras</button><button class="btn btn-secondary" style="padding:4px 8px; font-size:0.8rem; margin-right:4px;" onclick="App.views.formCliente('${c.id}')">✏️</button><button class="btn btn-secondary" style="padding:4px 8px; font-size:0.8rem; color:red; border-color:red;" onclick="App.logic.eliminarRegistroGenerico('clientes', '${c.id}', 'clientes')">🗑️</button></div></div>`; }); html += `</div><button class="fab" onclick="App.views.formCliente()">+</button>`; return html; };
App.views.proveedores = function() { document.getElementById('bottom-nav').style.display = 'flex'; let html = `<div class="card"><h3 class="card-title">Proveedores</h3>`; App.state.proveedores.forEach(p => { html += `<div class="card" style="border: 1px solid var(--border); padding: 10px; margin-bottom: 8px; display:flex; justify-content:space-between; align-items:center;"><div><strong>${App.ui.escapeHTML(p.nombre)}</strong><br><small style="color: var(--text-muted);">📞 ${p.telefono || 'N/A'}</small></div><div><button class="btn btn-secondary" style="padding:4px 8px; font-size:0.8rem; margin-right:4px;" onclick="App.views.formProveedor('${p.id}')">✏️</button><button class="btn btn-secondary" style="padding:4px 8px; font-size:0.8rem; color:red; border-color:red;" onclick="App.logic.eliminarRegistroGenerico('proveedores', '${p.id}', 'proveedores')">🗑️</button></div></div>`; }); html += `</div><button class="fab" onclick="App.views.formProveedor()">+</button>`; return html; };
App.views.artesanos = function() { document.getElementById('bottom-nav').style.display = 'flex'; let html = `<div class="card"><h3 class="card-title">Artesanos y Tareas</h3>`; App.state.artesanos.forEach(a => { html += `<div class="card" style="border: 1px solid var(--border); padding: 10px; margin-bottom: 8px; display:flex; justify-content:space-between; align-items:center;"><div><strong>${App.ui.escapeHTML(a.nombre)}</strong><br><small style="color: var(--text-muted);">📞 ${a.telefono || 'N/A'}</small></div><div><button class="btn btn-secondary" style="padding:4px 8px; font-size:0.8rem; margin-right:4px; border: 1px solid var(--primary); color: var(--primary); background: transparent;" onclick="App.views.verTarifasArtesano('${a.id}')">Tarifas 💲</button><button class="btn btn-secondary" style="padding:4px 8px; font-size:0.8rem; margin-right:4px;" onclick="App.views.formArtesano('${a.id}')">✏️</button><button class="btn btn-secondary" style="padding:4px 8px; font-size:0.8rem; color:red; border-color:red;" onclick="App.logic.eliminarRegistroGenerico('artesanos', '${a.id}', 'artesanos')">🗑️</button></div></div>`; }); html += `</div><button class="fab" onclick="App.views.formArtesano()">+</button>`; return html; };

App.views.verTarifasArtesano = function(artesanoId) { 
    const artesano = App.state.artesanos.find(a => a.id === artesanoId); const tarifas = App.state.tarifas_artesano.filter(t => t.artesano_id === artesanoId); 
    let html = `<div style="margin-bottom: 15px;">Gestiona cuánto cobra <strong>${App.ui.escapeHTML(artesano.nombre)}</strong> por cada tipo de tarea.</div><table style="width:100%; border-collapse: collapse; font-size: 0.9rem; margin-bottom:15px;"><tr style="border-bottom: 2px solid var(--border);"><th style="text-align:left; padding:8px;">Tipo de Trabajo</th><th style="padding:8px;">Monto</th><th></th></tr>`; 
    if(tarifas.length === 0) { html += `<tr><td colspan="3" style="padding:10px; color:#aaa; text-align:center;">Sin tareas configuradas</td></tr>`; } 
    else { tarifas.forEach(t => { html += `<tr style="border-bottom: 1px solid var(--border);"><td style="padding: 10px 5px;">${App.ui.escapeHTML(t.clasificacion) || 'Tarea'}</td><td style="padding: 10px 5px; text-align:center; font-weight:bold; color:var(--success)">$${t.monto || '0'}</td><td style="text-align:right;"><button class="btn btn-secondary" style="padding:4px 8px; font-size:0.8rem; margin-right:4px;" onclick="App.ui.closeSheet(); setTimeout(()=>App.views.formTarifa('${artesanoId}', '${t.id}'), 400);">✏️</button><button class="btn btn-secondary" style="padding:4px 8px; font-size:0.8rem; color:red; border-color:red;" onclick="App.logic.eliminarRegistroGenerico('tarifas_artesano', '${t.id}', 'tarifas_artesano'); App.ui.closeSheet();">🗑️</button></td></tr>`; }); } 
    html += `</table><button class="btn btn-primary" style="width:100%;" onclick="App.ui.closeSheet(); setTimeout(()=>App.views.formTarifa('${artesanoId}'), 400);">+ Agregar Tarea</button>`; App.ui.openSheet(`Tarifas de ${App.ui.escapeHTML(artesano.nombre)}`, html); 
};
App.views.formTarifa = function(artesanoId, tarifaId = null) { 
    if (typeof tarifaId !== 'string') tarifaId = null; const obj = tarifaId ? App.state.tarifas_artesano.find(t => t.id === tarifaId) : null; 
    const formHTML = `<form id="dynamic-form"><input type="hidden" name="artesano_id" value="${artesanoId}"><div class="form-group"><label>Tarea a Realizar (Ej. Tejer Cuerpo)</label><input type="text" name="clasificacion" value="${obj ? App.ui.escapeHTML(obj.clasificacion) : ''}" required placeholder="Nombre de la tarea"></div><div class="form-group"><label>Monto a Pagar ($)</label><input type="number" step="0.01" name="monto" value="${obj ? obj.monto : ''}" required></div><button type="submit" class="btn btn-primary" style="width: 100%; margin-top: 10px;">${obj ? 'Guardar Cambios' : 'Guardar Tarea'}</button></form>`; 
    App.ui.openSheet(obj ? "Editar Tarea" : "Nueva Tarea para Artesano", formHTML, (data) => { if (obj) { App.logic.actualizarRegistroGenerico("tarifas_artesano", tarifaId, data, "tarifas_artesano", () => { setTimeout(() => App.views.verTarifasArtesano(artesanoId), 400); }); } else { App.logic.guardarNuevoGenerico("tarifas_artesano", data, "TAR", "tarifas_artesano", () => { setTimeout(() => App.views.verTarifasArtesano(artesanoId), 400); }); } }); 
};

App.views.compras = function() { 
    document.getElementById('bottom-nav').style.display = 'flex'; let html = `<div class="card"><h3 class="card-title">Historial de Compras</h3>`; 
    [...(App.state.compras||[])].reverse().forEach(c => { const p = App.state.proveedores.find(prv => prv.id === c.proveedor_id); const deuda = parseFloat(c.total||0) - parseFloat(c.monto_pagado||c.total); html += `<div class="card" style="border: 1px solid var(--border); box-shadow: none;"><div style="display: flex; justify-content: space-between; margin-bottom: 5px;"><strong>${c.id}</strong>${deuda > 0 ? `<span class="badge" style="background:#FED7D7; color:#E53E3E;">Por pagar: $${deuda.toFixed(2)}</span>` : `<span class="badge" style="background:#C6F6D5; color:#38A169;">Pagado</span>`}</div><p style="color: var(--text-muted); font-size: 0.85rem; margin-bottom: 5px; cursor:pointer;" onclick="App.views.verDetallesCompra('${c.id}')">Proveedor: ${p ? App.ui.escapeHTML(p.nombre) : 'General'} | Fecha: ${c.fecha}<br><span style="color:var(--primary); font-weight:bold; display:inline-block; margin-top:5px;">👀 Ver artículos comprados</span></p><div style="text-align: right; border-top:1px dashed #eee; padding-top:8px; margin-top:8px;">${deuda > 0 ? `<button class="btn btn-secondary" style="padding:4px 8px; font-size:0.8rem; margin-right:4px; color:var(--success); border-color:var(--success);" onclick="App.views.formAbonarCompra('${c.id}', ${deuda})">💰 Abonar</button>` : ''}<button class="btn btn-secondary" style="padding:4px 8px; font-size:0.8rem; margin-right:4px;" onclick="App.views.formEditarCompra('${c.id}')">✏️ Editar</button><button class="btn btn-secondary" style="padding:4px 8px; font-size:0.8rem; color:red; border-color:red;" onclick="App.logic.eliminarCompra('${c.id}')">🗑️ Eliminar</button></div></div>`; }); 
    return html += `</div><button class="fab" onclick="App.views.formCompra()">+</button>`; 
};
App.views.verDetallesCompra = function(compraId) { const c = App.state.compras.find(x => x.id === compraId); const p = App.state.proveedores.find(prv => prv.id === c.proveedor_id); let detalles = []; try { detalles = JSON.parse(c.detalles || '[]'); } catch(e){} let detHTML = `<ul style="list-style:none; padding:0; margin:0;">`; if(detalles.length === 0) detHTML += `<li><small style="color:var(--text-muted)">Compra antigua sin detalles.</small></li>`; detalles.forEach(d => { detHTML += `<li style="padding:8px 0; border-bottom:1px dashed #ccc; display:flex; justify-content:space-between; align-items:center;"><span><strong style="color:var(--primary);">${d.cantidad}x</strong> ${App.ui.escapeHTML(d.nombre)}</span><span style="color:var(--text-muted); font-size:0.85rem;">$${d.costo_unitario} c/u</span></li>`; }); detHTML += `</ul>`; let html = `<div style="font-size:0.9rem; margin-bottom:15px;"><p style="margin:2px 0;"><strong>Proveedor:</strong> ${p ? App.ui.escapeHTML(p.nombre) : 'General'}</p><p style="margin:2px 0;"><strong>Fecha:</strong> ${c.fecha}</p><p style="margin:2px 0;"><strong>Total Pagado:</strong> <span style="color:var(--danger); font-weight:bold;">$${c.total}</span></p></div><h4 style="margin-top:15px; border-bottom:2px solid var(--primary); padding-bottom:5px; color:var(--primary-dark);">Artículos Comprados</h4><div style="background:#f9f9f9; padding:10px; border-radius:6px; margin-bottom:15px;">${detHTML}</div><button class="btn btn-primary" style="width:100%;" onclick="App.ui.closeSheet()">Cerrar</button>`; App.ui.openSheet(`Detalle de Compra`, html); };
App.views.configuracion = function() { return `<div class="card"><h3 class="card-title">Configuración</h3><button class="btn btn-primary" style="width: 100%; margin-bottom: 15px;" onclick="App.logic.descargarRespaldo()">💾 Descargar Respaldo JSON</button><button class="btn btn-secondary" style="width: 100%; margin-bottom: 15px; border-color:#38A169; color:#38A169; background:transparent;" onclick="window.exportarAExcel(App.state.movimientos_inventario, 'Kardex_Completo')">📥 Descargar Kardex a Excel</button><button class="btn btn-secondary" style="width: 100%; margin-bottom: 15px; border-color:#2B6CB0; color:#2B6CB0; background:transparent;" onclick="App.logic.verDiagnostico()">🛠️ Diagnóstico de Base de Datos</button><button class="btn btn-secondary" style="width: 100%; background: #FED7D7; color: var(--danger); border: none;" onclick="localStorage.removeItem('erp_session_token'); location.reload();">🔒 Cerrar Sesión</button></div>`; };
App.views.reparaciones = function() { 
    document.getElementById('bottom-nav').style.display = 'flex'; 
    let html = `<div class="card"><h3 class="card-title">Reparaciones</h3>`; 
    [...App.state.reparaciones].reverse().forEach(r => { 
        const c = App.state.clientes.find(cli => cli.id === r.cliente_id); 
        const pagos = App.state.pago_artesanos.filter(p => p.orden_id === r.id); 
        let infoArtesanos = pagos.length > 0 ? `🛠️ ${pagos.length} Trabajos asignados` : '👤 Sin asignar'; 
        const estaLista = r.estado === 'entregada'; 
        html += `<div class="card" style="border: 1px solid var(--border); box-shadow: none;"><div style="display: flex; justify-content: space-between; margin-bottom: 8px;"><strong>${r.id} - ${c ? App.ui.escapeHTML(c.nombre) : 'Cliente'}</strong><span class="badge ${estaLista ? 'listo' : 'pendiente'}">${String(r.estado || 'recibida').toUpperCase()}</span></div><p style="color: var(--primary); font-size: 0.9rem; font-weight: bold; margin-bottom: 5px;">${App.ui.escapeHTML(r.descripcion) || 'Reparación'}</p><div style="font-size:0.8rem; margin-bottom:5px; color:#4A5568; display:flex; justify-content:space-between;"><span>Cobro: <strong>$${r.precio || 0}</strong></span> <span>Pagado: <strong style="color:var(--success);">$${r.anticipo||0}</strong></span></div><div style="font-size:0.8rem; margin-bottom:10px; color:#4A5568;">${infoArtesanos}</div><div style="display:flex; justify-content:space-between; gap:5px; margin-bottom: 8px;">`; 
        if(!estaLista) { 
            html += `<button class="btn btn-secondary" style="font-size:0.8rem; padding:6px; flex:1;" onclick="App.views.formAgregarTrabajo('${r.id}', true)">+ Tarea Artesano</button>`; 
            html += `<button class="btn btn-primary" style="font-size:0.8rem; padding:6px; background:var(--success); border-color:var(--success); flex:1;" onclick="App.logic.actualizarReparacion('${r.id}', 'entregada')">✔ Marcar Lista</button>`; 
        } 
        html += `</div><div style="display:flex; gap:5px;"><button class="btn btn-secondary" style="padding:6px; font-size:0.8rem; flex:1; color:var(--primary); border-color:var(--primary);" onclick="App.logic.imprimirTicketReparacion('${r.id}')">🖨️ Ticket</button><button class="btn btn-secondary" style="padding:6px; font-size:0.8rem; flex:1;" onclick="App.views.formNuevaReparacion('${r.id}')">✏️ Editar</button><button class="btn btn-secondary" style="padding:6px; font-size:0.8rem; color:red;" onclick="App.logic.eliminarReparacion('${r.id}')">🗑️</button></div></div>`; 
    }); 
    return html += `</div><button class="fab" onclick="App.views.formNuevaReparacion()">+</button>`; 
};

