App.views.cotizaciones = function() { document.getElementById('bottom-nav').style.display = 'flex'; let html = `<div class="card"><h3 class="card-title">Cotizaciones Rápidas</h3><p style="color:var(--text-muted); font-size:0.85rem; margin-bottom:15px;">Solo informativas. No afectan inventario ni finanzas.</p>`; if (!App.state.cotizaciones || App.state.cotizaciones.length === 0) { html += `<p>No hay cotizaciones recientes.</p>`; } else { [...App.state.cotizaciones].reverse().forEach(c => { html += `<div class="card" style="border: 1px solid var(--border); box-shadow: none;"><div style="display: flex; justify-content: space-between; margin-bottom: 5px;"><strong>${c.id} - ${App.ui.escapeHTML(c.cliente_nombre)}</strong><span style="color: var(--primary); font-weight: bold;">$${c.total}</span></div><p style="color: var(--text-muted); font-size: 0.85rem; margin-bottom: 5px;">${App.ui.escapeHTML(c.descripcion)}</p><div style="display:flex; gap:5px; justify-content:flex-end;"><button class="btn btn-secondary" style="padding:4px 8px; font-size:0.8rem; margin-right:4px;" onclick="App.logic.imprimirCotizacion('${c.id}')">🖨️ Imprimir PDF</button><button class="btn btn-secondary" style="padding:4px 8px; font-size:0.8rem; color:red; border-color:red;" onclick="App.logic.eliminarCotizacion('${c.id}')">🗑️</button></div></div>`; }); } html += `</div><button class="fab" onclick="App.views.formNuevaCotizacion()">+</button>`; return html; };

App.views.formGasto = function(id = null) { if (typeof id !== 'string') id = null; const obj = id ? App.state.gastos.find(g => g.id === id) : null; let htmlGastos = ''; if(obj) { htmlGastos = `<div class="form-group"><label>Descripción del Gasto</label><input type="text" name="descripcion" value="${App.ui.escapeHTML(obj.descripcion)}" required></div><div class="form-group"><label>Monto ($)</label><input type="number" step="0.01" name="monto" value="${obj.monto}" required></div>`; } else { htmlGastos = `<div id="cont-gastos"><div class="grid-2 fila-dinamica" style="margin-bottom: 5px;"><div class="form-group" style="margin:0;"><input type="text" name="descripcion[]" placeholder="Descripción" required></div><div class="form-group" style="margin:0; display:flex; gap:5px;"><input type="number" step="0.01" name="monto[]" placeholder="$ Monto" required></div></div></div><button type="button" class="btn btn-secondary" style="width:100%; margin-top:10px; margin-bottom:15px; border:1px dashed var(--danger); color:var(--danger); background: transparent;" onclick="window.agregarFilaGasto()">+ Añadir Gasto a la lista</button>`; } const formHTML = `<form id="dynamic-form"><div class="form-group"><label>Categoría</label><select name="categoria" required><option value="Materiales e Insumos" ${obj && obj.categoria === 'Materiales e Insumos' ? 'selected' : ''}>Materiales (Hilos, Accesorios)</option><option value="Hamacas (Reventa)" ${obj && obj.categoria === 'Hamacas (Reventa)' ? 'selected' : ''}>Hamacas (Reventa)</option><option value="Servicios y Otros" ${obj && obj.categoria === 'Servicios y Otros' ? 'selected' : ''}>Servicios</option><option value="Nómina Artesanos" ${obj && obj.categoria === 'Nómina Artesanos' ? 'selected' : ''}>Nómina</option><option value="Otros Gastos" ${obj && obj.categoria === 'Otros Gastos' ? 'selected' : ''}>Otro</option></select></div><div class="form-group"><label>Fecha</label><input type="date" name="fecha" value="${obj ? obj.fecha : new Date().toISOString().split('T')[0]}" required></div>${htmlGastos}<button type="submit" class="btn btn-primary" style="width: 100%; background: var(--danger); border-color: var(--danger);">${obj ? 'Guardar Cambios' : 'Registrar Gastos'}</button></form>`; App.ui.openSheet(obj ? "Editar Gasto" : "Nuevos Gastos Múltiples", formHTML, (data) => { if (obj) App.logic.actualizarRegistroGenerico("gastos", id, data, "gastos"); else App.logic.guardarMultiplesGastos(data); }); };
App.views.formCompra = function() { const opcProv = App.state.proveedores.map(p => `<option value="${p.id}">${App.ui.escapeHTML(p.nombre)}</option>`).join(''); const opcMat = App.state.inventario.map(m => `<option value="${m.id}">${App.ui.escapeHTML(m.nombre)} (Stock: ${m.stock_actual})</option>`).join(''); const formHTML = `<form id="dynamic-form"><div class="form-group"><div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:5px;"><label style="margin:0;">Proveedor</label><span style="color:var(--primary); font-size:0.8rem; cursor:pointer; font-weight:bold;" onclick="App.ui.closeSheet(); setTimeout(()=>App.views.formProveedor(null, () => App.views.formCompra()), 400);">+ Nuevo Proveedor</span></div><select name="proveedor_id" required><option value="">-- Elige Proveedor --</option>${opcProv}</select></div><div style="background: #EBF8FF; padding: 10px; border-radius: 8px; margin-bottom: 15px;"><strong style="font-size: 0.9rem; color: var(--primary);">📥 Artículos Comprados (Dinámico)</strong><br><div style="text-align:center; margin:10px 0;"><button type="button" class="btn btn-secondary" style="border:2px dashed var(--primary); color:var(--primary); padding:8px; width:100%; background: transparent;" onclick="App.ui.closeSheet(); setTimeout(()=>App.views.formMaterial(null, () => App.views.formCompra()), 400);">+ Crear Insumo Nuevo</button></div><div id="cont-compras"><div class="fila-compra" style="background: white; padding: 10px; border-radius: 6px; border: 1px solid #e2e8f0; margin-bottom: 10px;"><div style="margin-bottom: 5px;"><select name="mat_id[]" required style="width: 100%;"><option value="">-- Selecciona Insumo --</option>${opcMat}</select></div><div style="display: flex; gap: 5px; align-items: center;"><input type="number" step="0.1" name="cant[]" placeholder="Cant." required oninput="window.calcTotalCompra()" style="flex: 1; padding: 6px; min-width: 0;"><input type="number" step="0.01" name="precio_u[]" placeholder="$ Unit." required oninput="window.calcTotalCompra()" style="flex: 1; padding: 6px; min-width: 0;"><input type="number" step="0.01" name="total_fila[]" placeholder="$ Tot" readonly style="flex: 1; padding: 6px; background: #edf2f7; min-width: 0;"><button type="button" onclick="this.parentElement.parentElement.remove(); window.calcTotalCompra();" style="background: var(--danger); color: white; border: none; border-radius: 4px; padding: 6px 10px; font-weight: bold;">X</button></div></div></div><button type="button" class="btn btn-secondary" style="width:100%; margin-top:10px; border:1px dashed #3182CE; color:#3182CE; background: transparent;" onclick="window.agregarFilaCompra()">+ Añadir otro artículo</button></div><div class="form-group"><label>Fecha</label><input type="date" name="fecha" value="${new Date().toISOString().split('T')[0]}" required></div><div class="grid-2"><div class="form-group"><label>Total Factura ($)</label><input type="number" step="0.01" name="total" required readonly style="background:#f0f0f0; font-weight:bold;"></div><div class="form-group"><label>Monto Pagado Hoy ($)</label><input type="number" step="0.01" name="monto_pagado" required></div></div><button type="submit" class="btn btn-primary" style="width: 100%; margin-top: 10px; background: var(--success); border-color: var(--success);">Confirmar Compra</button></form>`; App.ui.openSheet("Ingresar Compra", formHTML, (data) => App.logic.guardarNuevaCompra(data)); };
App.views.formAbonarCompra = function(compraId, saldoPendiente) { const formHTML = `<form id="dynamic-form"><input type="hidden" name="compra_id" value="${compraId}"><div class="form-group"><label>Abonar a Proveedor ($)</label><input type="number" step="0.01" name="monto" value="${saldoPendiente}" max="${saldoPendiente}" required></div><button type="submit" class="btn btn-primary" style="width: 100%;">Registrar Abono</button></form>`; App.ui.openSheet(`Abono a Compra ${compraId.replace('COM-','')}`, formHTML, (data) => App.logic.guardarAbonoCompra(data)); };
App.views.formEditarCompra = function(id) { const obj = App.state.compras.find(c => c.id === id); const opcProv = App.state.proveedores.map(p => `<option value="${p.id}" ${obj.proveedor_id === p.id ? 'selected':''}>${App.ui.escapeHTML(p.nombre)}</option>`).join(''); const formHTML = `<form id="dynamic-form"><div style="background: #F7FAFC; padding: 10px; border-radius: 8px; margin-bottom: 15px; font-size: 0.85rem; border: 1px solid var(--border);"><strong>Nota:</strong> Solo puedes cambiar Proveedor, Fecha y Total. Para cambiar cantidades, ELIMINA la compra y vuelve a hacerla.</div><div class="form-group"><label>Proveedor</label><select name="proveedor_id" required><option value="">-- Elige Proveedor --</option>${opcProv}</select></div><div class="form-group"><label>Fecha</label><input type="date" name="fecha" value="${obj.fecha}" required></div><div class="form-group"><label>Costo Total Pagado ($)</label><input type="number" name="total" value="${obj.total}" required></div><button type="submit" class="btn btn-primary" style="width: 100%; margin-top: 10px;">Guardar Cambios</button></form>`; App.ui.openSheet("Editar Compra", formHTML, (data) => App.logic.actualizarRegistroGenerico("compras", id, data, "compras")); };
App.views.formNuevaReparacion = function(id = null) { const obj = id ? App.state.reparaciones.find(r => r.id === id) : null; const opcionesClientes = App.state.clientes.map(c => `<option value="${c.id}" ${obj && obj.cliente_id === c.id ? 'selected' : ''}>${App.ui.escapeHTML(c.nombre)}</option>`).join(''); const formHTML = `<form id="dynamic-form"><div class="form-group"><div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:5px;"><label style="margin:0;">Cliente</label><span style="color:var(--primary); font-size:0.8rem; cursor:pointer; font-weight:bold;" onclick="App.ui.closeSheet(); setTimeout(()=>App.views.formCliente(null, () => App.views.formNuevaReparacion('${id||''}')), 400);">+ Nuevo Cliente</span></div><select name="cliente_id" required><option value="">-- Elige un cliente --</option>${opcionesClientes}</select></div><div class="form-group"><label>Descripción del Problema</label><input type="text" name="descripcion" value="${obj ? App.ui.escapeHTML(obj.descripcion) : ''}" required placeholder="Ej. Cambio de brazos"></div><div class="form-group"><label>Costo Total de la Reparación ($)</label><input type="number" step="0.01" name="precio" value="${obj ? obj.precio : ''}" required></div><div class="form-group"><label>Importe Pagado / Anticipo ($)</label><input type="number" step="0.01" name="anticipo" value="${obj ? obj.anticipo : '0'}" required></div>${obj ? `<div class="form-group"><label>Estado</label><select name="estado"><option value="recibida" ${obj.estado === 'recibida' ? 'selected' : ''}>Recibida / Pendiente</option><option value="entregada" ${obj.estado === 'entregada' ? 'selected' : ''}>Lista / Entregada</option></select></div>` : ''}<button type="submit" class="btn btn-primary" style="width: 100%; margin-top: 10px;">${obj ? 'Guardar Cambios' : 'Registrar Reparación'}</button></form>`; App.ui.openSheet(obj ? "Editar Reparación" : "Nueva Reparación", formHTML, (data) => { if (obj) App.logic.actualizarRegistroGenerico("reparaciones", id, data, "reparaciones"); else App.logic.guardarNuevaReparacion(data); }); };
App.views.formCerrarOrden = function(ordenId) { const orden = App.state.ordenes_produccion.find(o => o.id === ordenId); const detalle = App.state.pedido_detalle.find(d => d.id === orden.pedido_detalle_id) || App.state.pedido_detalle.find(d => d.pedido_id === orden.pedido_detalle_id) || {}; const producto = detalle.producto_id ? App.state.productos.find(p => p.id === detalle.producto_id) : { nombre: 'Hamaca', tubos_hilo: 0 }; let materialesHTML = ''; let recetaGuardada = null; try { if(orden.receta_personalizada) recetaGuardada = JSON.parse(orden.receta_personalizada); } catch(e){} if (recetaGuardada && recetaGuardada.length > 0) { recetaGuardada.forEach((item, index) => { const material = App.state.inventario.find(m => m.id === item.mat_id); if(material) { materialesHTML += `<div class="form-group" style="margin-bottom:8px; background: white; padding: 8px; border-radius: 4px; border: 1px solid #e2e8f0;"><label>${App.ui.escapeHTML(material.nombre)} <strong style="color:var(--primary);">[${(item.uso||'Cuerpo').toUpperCase()}]</strong></label><input type="hidden" name="mat_${index+1}_id" value="${item.mat_id}"><input type="hidden" name="mat_${index+1}_teorico" value="${item.cant}"><div style="display:flex; align-items:center; gap: 10px;"><span style="font-size:0.8rem;">Consumo Real:</span><input type="number" step="0.1" name="mat_${index+1}_real" value="${item.cant}" required style="flex:1;"></div></div>`; } }); } else { for(let i=1; i<=20; i++){ const matId = producto[`mat_${i}`]; const cant = parseFloat(producto[`cant_${i}`]); const uso = producto[`uso_${i}`] || 'Cuerpo'; if(matId && cant > 0) { const material = App.state.inventario.find(m => m.id === matId); const consumoTeorico = cant * parseInt(detalle.cantidad || 1); materialesHTML += `<div class="form-group" style="margin-bottom:8px; background: white; padding: 8px; border-radius: 4px; border: 1px solid #e2e8f0;"><label>${material ? App.ui.escapeHTML(material.nombre) : 'Insumo'} <strong style="color:var(--primary);">[${uso.toUpperCase()}]</strong></label><input type="hidden" name="mat_${i}_id" value="${matId}"><input type="hidden" name="mat_${i}_teorico" value="${consumoTeorico}"><div style="display:flex; align-items:center; gap: 10px;"><span style="font-size:0.8rem;">Consumo Real:</span><input type="number" step="0.1" name="mat_${i}_real" value="${consumoTeorico}" required style="flex:1;"></div></div>`; } } } if(materialesHTML === '') materialesHTML = '<p style="color:var(--text-muted); font-size:0.8rem;">No hay insumos a descontar para este producto.</p>'; const formHTML = `<div style="background: #EBF8FF; padding: 10px; border-radius: 8px; margin-bottom: 15px; font-size: 0.9rem; color: #2B6CB0;"><strong>Cierre de Producción</strong><br>Producto: ${App.ui.escapeHTML(producto.nombre)}</div><form id="dynamic-form"><input type="hidden" name="orden_id" value="${ordenId}"><p style="font-size:0.8rem; color:var(--text-muted); margin-bottom:10px;">Si hubo merma y usaron más hilo del apartado, ajústalo aquí.</p>${materialesHTML}<div style="margin-top: 15px; padding: 10px; background: #E2E8F0; border-radius: 6px;"><label style="display:flex; align-items:center; gap:8px;"><input type="checkbox" name="sumar_stock" value="1" style="width:20px; height:20px;"><strong>Guardar en mi Bodega Física</strong></label><small style="color:var(--text-muted); display:block; margin-top:5px;">Si esta hamaca NO se va a entregar a un cliente hoy, marca esta casilla para guardarla en tu inventario de reventa.</small></div><button type="submit" class="btn btn-primary" style="width: 100%; margin-top: 15px; background: var(--success); border-color: var(--success);">Finalizar Orden</button></form>`; App.ui.openSheet("Cerrar Orden", formHTML, (datos) => App.logic.cerrarOrdenProduccion(datos)); };
App.views.formMandarProduccion = function(pedidoId) { const pedido = App.state.pedidos.find(p => p.id === pedidoId); const detalle = App.state.pedido_detalle.find(d => d.pedido_id === pedidoId); const producto = App.state.productos.find(p => p.id === detalle.producto_id); let recetaHTML = ''; if (producto) { let counter = 1; while(producto[`mat_${counter}`]) { const matId = producto[`mat_${counter}`]; const cant = parseFloat(producto[`cant_${counter}`]) * (parseInt(detalle.cantidad) || 1); const uso = producto[`uso_${counter}`] || 'Cuerpo'; if(matId) recetaHTML += window.generarFilaRecetaProd(matId, cant, uso); counter++; } } if (recetaHTML === '') recetaHTML = window.generarFilaRecetaProd('','','Cuerpo'); const formHTML = `<form id="dynamic-form"><input type="hidden" name="pedido_id" value="${pedidoId}"><input type="hidden" name="pedido_detalle_id" value="${detalle.id}"><div style="background: #EBF8FF; padding: 10px; border-radius: 8px; margin-bottom: 15px; font-size: 0.85rem; color: #2B6CB0;"><strong>Confirmar Insumos para Producción</strong><br>El inventario se descontará en este momento. Puedes ajustar los colores si el cliente pidió algo especial.</div><div id="cont-receta-prod">${recetaHTML}</div><button type="button" class="btn btn-secondary" style="width:100%; margin-top:10px; border: 1px dashed var(--primary); color: var(--primary); background: transparent;" onclick="window.agregarFilaRecetaProd()">+ Añadir insumo extra</button><button type="submit" class="btn btn-primary" style="width: 100%; margin-top: 15px; background: var(--success); border-color: var(--success);">Confirmar y Enviar a Taller</button></form>`; App.ui.openSheet("Mandar a Producción", formHTML, (data) => App.logic.confirmarMandarProduccion(data)); };
App.views.formNuevaCotizacion = function() { const formHTML = `<form id="dynamic-form"><div style="background: #EEF2FF; padding: 10px; border-radius: 8px; margin-bottom: 15px; font-size: 0.85rem; color: #4C51BF;">📝 Las cotizaciones no restan inventario ni se suman a las finanzas.</div><div class="form-group"><label>Nombre del Cliente</label><input type="text" name="cliente_nombre" required></div><div class="form-group"><label>Descripción (Ej. Hamaca Matrimonial)</label><input type="text" name="descripcion" required></div><div class="form-group"><label>Precio Cotizado ($)</label><input type="number" step="0.01" name="total" required></div><button type="submit" class="btn btn-primary" style="width: 100%;">Generar Cotización y PDF</button></form>`; App.ui.openSheet("Nueva Cotización", formHTML, (data) => App.logic.guardarCotizacion(data)); };

App.views.formMaterial = function(id = null, callback = null) { 
    const obj = id ? App.state.inventario.find(m => m.id === id) : null; 
    const formHTML = `<form id="dynamic-form"><div style="background: #EBF8FF; padding: 10px; border-radius: 8px; margin-bottom: 15px; font-size: 0.85rem; color: #2B6CB0;">Crea o ajusta un insumo.</div><div class="form-group"><label>Nombre del Insumo / Artículo</label><input type="text" name="nombre" value="${obj ? App.ui.escapeHTML(obj.nombre) : ''}" required placeholder="Ej. Hilo Nylon Rojo"></div><div class="form-group"><label>Tipo de Insumo</label><select name="tipo" required><option value="hilo" ${obj && obj.tipo === 'hilo' ? 'selected' : ''}>Hilo para Tejer</option><option value="accesorio" ${obj && obj.tipo === 'accesorio' ? 'selected' : ''}>Accesorios (Argollas, etc)</option><option value="reventa" ${obj && obj.tipo === 'reventa' ? 'selected' : ''}>Hamaca Terminada (Reventa)</option><option value="otro" ${obj && obj.tipo === 'otro' ? 'selected' : ''}>Otro</option></select></div><div class="form-group"><label>Unidad de Medida</label><select name="unidad"><option value="Tubos" ${obj && obj.unidad === 'Tubos' ? 'selected' : ''}>Tubos</option><option value="Kg" ${obj && obj.unidad === 'Kg' ? 'selected' : ''}>Kilogramos (Kg)</option><option value="Pzas" ${obj && obj.unidad === 'Pzas' ? 'selected' : ''}>Piezas (Pzas)</option></select></div><div class="grid-2"><div class="form-group"><label>Stock Real (Físico)</label><input type="number" step="0.1" name="stock_real" value="${obj ? obj.stock_real : '0'}" required></div><div class="form-group"><label>Stock Mínimo (Alerta)</label><input type="number" step="0.1" name="stock_minimo" value="${obj ? (obj.stock_minimo||'0') : '0'}" required></div></div><button type="submit" class="btn btn-primary" style="width: 100%;">${obj ? 'Guardar Cambios' : 'Crear Insumo'}</button></form>`; 
    App.ui.openSheet(obj ? "Editar Insumo" : "Nuevo Insumo", formHTML, (data) => { 
        if (obj) App.logic.actualizarRegistroGenerico("materiales", id, data, "inventario"); 
        else { data.stock_reservado = 0; data.stock_comprometido = 0; App.logic.guardarNuevoGenerico("materiales", data, "MAT", "inventario", callback); } 
    }); 
};

App.views.formProducto = function(id = null, callback = null) { const obj = id ? App.state.productos.find(p => p.id === id) : null; const generarFila = (matId, cant, uso) => { const opcMat = App.state.inventario.map(m => `<option value="${m.id}" ${matId === m.id ? 'selected':''}>${App.ui.escapeHTML(m.nombre)} (${App.ui.escapeHTML(m.unidad)})</option>`).join(''); return `<div class="grid-3 fila-dinamica" style="margin-bottom: 5px;"><div class="form-group" style="margin:0;"><select name="mat_id[]" required><option value="">-- Insumo --</option>${opcMat}</select></div><div class="form-group" style="margin:0;"><input type="number" step="0.1" name="cant[]" value="${cant||''}" placeholder="Cant" required></div><div class="form-group" style="margin:0; display:flex; gap:5px;"><select name="uso[]" required><option value="Cuerpo" ${uso==='Cuerpo'?'selected':''}>Cuerpo</option><option value="Brazos" ${uso==='Brazos'?'selected':''}>Brazos</option><option value="Adicional" ${uso==='Adicional'?'selected':''}>Otro</option></select><button type="button" onclick="this.parentElement.parentElement.remove()" style="background:var(--danger); color:white; border:none; border-radius:4px; padding:0 10px;">X</button></div></div>`; }; let recetaHTML = ''; let counter = 1; if (obj) { while(obj[`mat_${counter}`]) { recetaHTML += generarFila(obj[`mat_${counter}`], obj[`cant_${counter}`], obj[`uso_${counter}`]); counter++; } } if (recetaHTML === '') recetaHTML = generarFila('','',''); const clasif = obj ? obj.clasificacion : ''; const formHTML = `<form id="dynamic-form"><div class="form-group"><label>Nombre del Producto a Vender</label><input type="text" name="nombre" value="${obj ? App.ui.escapeHTML(obj.nombre) : ''}" required></div><div class="grid-2"><div class="form-group"><label>Categoría</label><select name="categoria"><option value="fabricacion" ${obj && obj.categoria === 'fabricacion' ? 'selected' : ''}>Fabricación</option><option value="reventa" ${obj && obj.categoria === 'reventa' ? 'selected' : ''}>Reventa</option></select></div><div class="form-group"><label>Clasificación</label><select name="clasificacion"><option value="Unicolor" ${clasif==='Unicolor'?'selected':''}>Unicolor</option><option value="Combinada" ${clasif==='Combinada'?'selected':''}>Combinada</option><option value="Especial" ${clasif==='Especial'?'selected':''}>Especial</option><option value="Reventa" ${clasif==='Reventa'?'selected':''}>Reventa</option><option value="Otro" ${clasif==='Otro'?'selected':''}>Otro</option></select></div></div><div class="grid-2"><div class="form-group"><label>Tamaño</label><input type="text" name="tamano" value="${obj ? App.ui.escapeHTML(obj.tamano||'') : ''}" placeholder="Ej. Matrimonial"></div><div class="form-group"><label>Color</label><input type="text" name="color" value="${obj ? App.ui.escapeHTML(obj.color||'') : ''}" placeholder="Ej. Rojo/Blanco"></div></div><div class="grid-2"><div class="form-group"><label>Precio Venta ($)</label><input type="number" name="precio_venta" value="${obj ? obj.precio_venta : ''}" required></div><div class="form-group"><label>Precio Mayoreo ($)</label><input type="number" name="precio_mayoreo" value="${obj ? (obj.precio_mayoreo||'') : ''}"></div></div><div style="background: #F7FAFC; padding: 10px; border-radius: 8px; margin-bottom: 15px; border: 1px solid var(--border);"><strong style="font-size: 0.9rem; color: var(--primary);">📦 Receta de Inventario (Dinámica)</strong><div id="cont-receta" style="margin-top:10px;">${recetaHTML}</div><button type="button" class="btn btn-secondary" style="width:100%; margin-top:10px; border: 1px dashed var(--primary); color: var(--primary); background: transparent;" onclick="window.agregarFilaReceta()">+ Añadir Insumo a la Receta</button></div><button type="submit" class="btn btn-primary" style="width: 100%;">${obj ? 'Guardar Cambios' : 'Crear Producto'}</button></form>`; App.ui.openSheet(obj ? "Editar Producto" : "Nuevo Producto", formHTML, (data) => { if (data.mat_id && Array.isArray(data.mat_id)) { for(let i=0; i<data.mat_id.length; i++) { data[`mat_${i+1}`] = data.mat_id[i]; data[`cant_${i+1}`] = data.cant[i]; data[`uso_${i+1}`] = data.uso[i]; } delete data.mat_id; delete data.cant; delete data.uso; } else if(data.mat_id) { data.mat_1 = data.mat_id; data.cant_1 = data.cant; data.uso_1 = data.uso; delete data.mat_id; delete data.cant; delete data.uso; } if (obj) App.logic.actualizarRegistroGenerico("productos", id, data, "productos"); else App.logic.guardarNuevoGenerico("productos", data, "PROD", "productos", callback); }); };
App.views.formCliente = function(id = null, callback = null) { const obj = id ? App.state.clientes.find(c => c.id === id) : null; const formHTML = `<form id="dynamic-form"><div class="form-group"><label>Nombre</label><input type="text" name="nombre" value="${obj ? App.ui.escapeHTML(obj.nombre) : ''}" required></div><div class="form-group"><label>Teléfono (10 dígitos)</label><input type="tel" name="telefono" value="${obj ? obj.telefono : ''}" pattern="\\d{10}" title="El teléfono debe tener exactamente 10 números sin espacios" maxlength="10"></div><div class="form-group"><label>Dirección</label><input type="text" name="direccion" value="${obj ? App.ui.escapeHTML(obj.direccion) : ''}"></div><button type="submit" class="btn btn-primary" style="width: 100%;">${obj ? 'Guardar Cambios' : 'Crear Cliente'}</button></form>`; App.ui.openSheet(obj ? "Editar Cliente" : "Nuevo Cliente", formHTML, (data) => { if (obj) App.logic.actualizarRegistroGenerico("clientes", id, data, "clientes"); else App.logic.guardarNuevoGenerico("clientes", data, "CLI", "clientes", callback); }); };
App.views.formProveedor = function(id = null, callback = null) { const obj = id ? App.state.proveedores.find(p => p.id === id) : null; const formHTML = `<form id="dynamic-form"><div class="form-group"><label>Nombre del Proveedor</label><input type="text" name="nombre" value="${obj ? App.ui.escapeHTML(obj.nombre) : ''}" required></div><div class="form-group"><label>Teléfono (10 dígitos)</label><input type="tel" name="telefono" value="${obj ? obj.telefono : ''}" pattern="\\d{10}" title="El teléfono debe tener exactamente 10 números sin espacios" maxlength="10"></div><button type="submit" class="btn btn-primary" style="width: 100%;">${obj ? 'Guardar Cambios' : 'Crear Proveedor'}</button></form>`; App.ui.openSheet(obj ? "Editar Proveedor" : "Nuevo Proveedor", formHTML, (data) => { if (obj) App.logic.actualizarRegistroGenerico("proveedores", id, data, "proveedores"); else App.logic.guardarNuevoGenerico("proveedores", data, "PRV", "proveedores", callback); }); };
App.views.formArtesano = function(id = null) { const obj = id ? App.state.artesanos.find(a => a.id === id) : null; const formHTML = `<form id="dynamic-form"><div class="form-group"><label>Nombre del Artesano</label><input type="text" name="nombre" value="${obj ? App.ui.escapeHTML(obj.nombre) : ''}" required></div><div class="form-group"><label>Teléfono (10 dígitos)</label><input type="tel" name="telefono" value="${obj ? obj.telefono : ''}" pattern="\\d{10}" title="El teléfono debe tener exactamente 10 números sin espacios" maxlength="10"></div><button type="submit" class="btn btn-primary" style="width: 100%;">${obj ? 'Guardar Cambios' : 'Crear Artesano'}</button></form>`; App.ui.openSheet(obj ? "Editar Artesano" : "Nuevo Artesano", formHTML, (data) => { if (obj) App.logic.actualizarRegistroGenerico("artesanos", id, data, "artesanos"); else App.logic.guardarNuevoGenerico("artesanos", data, "ART", "artesanos"); }); };
App.views.formEditarPedido = function(id) { const p = App.state.pedidos.find(x => x.id === id); const fechaC = p.fecha_creacion ? p.fecha_creacion.split('T')[0] : ''; const formHTML = `<form id="dynamic-form"><div class="form-group"><label>Fecha de Solicitud</label><input type="date" name="fecha_creacion" value="${fechaC}" required></div><div class="form-group"><label>Precio Total ($)</label><input type="number" step="0.01" name="total" value="${p.total}" required></div><div class="form-group"><label>Anticipo Registrado ($)</label><input type="number" step="0.01" name="anticipo" value="${p.anticipo}" required></div><div class="form-group"><label>Fecha de Entrega</label><input type="date" name="fecha_entrega" value="${p.fecha_entrega || ''}"></div><div class="form-group"><label>Notas / Instrucciones</label><textarea name="notas" rows="2">${App.ui.escapeHTML(p.notas || '')}</textarea></div><button type="submit" class="btn btn-primary" style="width: 100%;">Guardar Cambios</button></form>`; App.ui.openSheet("Editar Pedido", formHTML, (data) => { if(data.fecha_creacion) data.fecha_creacion = data.fecha_creacion + "T12:00:00.000Z"; App.logic.actualizarRegistroGenerico("pedidos", id, data, "pedidos"); }); };
App.views.formNuevoPedido = function() { const opcionesClientes = App.state.clientes.map(c => `<option value="${c.id}">${App.ui.escapeHTML(c.nombre)}</option>`).join(''); const opcionesProductos = App.state.productos.map(p => `<option value="${p.id}">${App.ui.escapeHTML(p.nombre)}</option>`).join(''); const hoy = new Date().toISOString().split('T')[0]; const formHTML = `<form id="dynamic-form"><div style="background: #EBF8FF; padding: 8px; border-radius: 6px; margin-bottom: 10px; font-size: 0.8rem; color: #2B6CB0;"><strong>Novedad:</strong> El inventario de reventa se descontará automáticamente aquí. Si es fabricación, se descontará al mandar a Producción.</div><div class="form-group"><div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:5px;"><label style="margin:0;">Cliente</label><span style="color:var(--primary); font-size:0.8rem; cursor:pointer; font-weight:bold;" onclick="App.ui.closeSheet(); setTimeout(()=>App.views.formCliente(null, () => App.views.formNuevoPedido()), 400);">+ Nuevo Cliente</span></div><select name="cliente_id" required><option value="">-- Elige un cliente --</option>${opcionesClientes}</select></div><div class="form-group"><div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:5px;"><label style="margin:0;">Producto</label><span style="color:var(--primary); font-size:0.8rem; cursor:pointer; font-weight:bold;" onclick="App.ui.closeSheet(); setTimeout(()=>App.views.formProducto(null, () => App.views.formNuevoPedido()), 400);">+ Nuevo Producto</span></div><select name="producto_id" required onchange="window.calcularTotalPedido()"><option value="">-- Elige un producto --</option>${opcionesProductos}</select></div><div id="info-extra-prod" style="margin-top:-10px; margin-bottom:10px;"></div><div class="form-group"><label style="display:flex; align-items:center; gap:8px;"><input type="checkbox" name="es_mayoreo" value="1" onchange="window.calcularTotalPedido()" style="width:20px; height:20px;"><strong>Aplicar Precio Mayoreo</strong></label></div><div class="grid-2"><div class="form-group"><label>Fecha Solicitud</label><input type="date" name="fecha_creacion" value="${hoy}" required></div><div class="form-group"><label>Fecha Entrega</label><input type="date" name="fecha_entrega" required></div></div><div class="grid-2"><div class="form-group"><label>Cantidad</label><input type="number" name="cantidad" value="1" min="1" required oninput="window.calcularTotalPedido()"></div><div class="form-group"><label>Precio Total ($)</label><input type="number" name="total" required></div></div><div class="form-group"><label>Anticipo ($)</label><input type="number" name="anticipo" value="0" required></div><div class="form-group"><label>Notas</label><input type="text" name="notas" placeholder="Opcional"></div><button type="submit" class="btn btn-primary" style="width: 100%; margin-top: 10px;">Crear Pedido</button></form>`; App.ui.openSheet("Nuevo Pedido", formHTML, (data) => App.logic.guardarNuevoPedido(data)); };
App.views.formOrdenStock = function() { const opcionesProductos = App.state.productos.map(p => `<option value="${p.id}">${App.ui.escapeHTML(p.nombre)}</option>`).join(''); const formHTML = `<form id="dynamic-form"><div style="background: #F7FAFC; padding: 10px; border-radius: 8px; margin-bottom: 15px; font-size: 0.85rem; border: 1px solid var(--border);"><strong>Fabricar para Bodega</strong><br>Descontará hilos y enviará el trabajo a artesanos.</div><div class="form-group"><div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:5px;"><label style="margin:0;">¿Qué vas a fabricar?</label><span style="color:var(--primary); font-size:0.8rem; cursor:pointer; font-weight:bold;" onclick="App.ui.closeSheet(); setTimeout(()=>App.views.formProducto(null, () => App.views.formOrdenStock()), 400);">+ Nuevo Producto</span></div><select name="producto_id" required><option value="">-- Elige un producto --</option>${opcionesProductos}</select></div><div class="form-group"><label>Cantidad a fabricar</label><input type="number" name="cantidad" value="1" min="1" required></div><button type="submit" class="btn btn-primary" style="width: 100%; margin-top: 10px;">Mandar a Producción</button></form>`; App.ui.openSheet("Producir para Stock", formHTML, (data) => App.logic.guardarOrdenStock(data)); };
App.views.formCobrar = function(pedidoId, clienteId, saldoPendiente) { const formHTML = `<form id="dynamic-form"><input type="hidden" name="pedido_id" value="${pedidoId}"><input type="hidden" name="cliente_id" value="${clienteId}"><div class="form-group"><label>Abonar ($)</label><input type="number" name="monto" value="${saldoPendiente}" max="${saldoPendiente}" required></div><div class="form-group"><label>Nota/Método</label><input type="text" name="nota" value="Efectivo" required></div><button type="submit" class="btn btn-primary" style="width: 100%;">Confirmar Pago</button></form>`; App.ui.openSheet(`Pago ${pedidoId}`, formHTML, (data) => App.logic.guardarAbono(data)); };
App.views.formAgregarTrabajo = function(ordenId, esReparacion = false) { const opcArt = App.state.artesanos.map(a => `<option value="${a.id}">${App.ui.escapeHTML(a.nombre)}</option>`).join(''); const formHTML = `<form id="dynamic-form"><div class="form-group"><label>Artesano</label><select name="artesano_id" required onchange="window.cargarTarifas(this.value)"><option value="">-- Selecciona --</option>${opcArt}</select></div><div class="form-group"><label>Tarea a Realizar</label><select name="tarea_val" id="select-tarifas" required onchange="window.calcTotalTrabajo()"><option value="">-- Elige un artesano primero --</option></select></div><input type="hidden" name="tarea_nombre" id="tarea_nombre"><div class="form-group"><label>Cantidad (Ej. 7 hilos, o 1 pza)</label><input type="number" step="0.1" name="cantidad" id="cant-trabajo" value="1" required oninput="window.calcTotalTrabajo()"></div><div class="form-group"><label>Total a Pagar ($)</label><input type="number" step="0.01" name="total" id="total-trabajo" required readonly style="background:#f0f0f0;"></div><button type="submit" class="btn btn-primary" style="width: 100%; margin-top: 10px;">Guardar Trabajo</button></form>`; App.ui.openSheet("Añadir Tarea", formHTML, (data) => App.logic.guardarTrabajoOrden(ordenId, data, esReparacion)); };
App.views.modalEditarOrden = function(ordenId) { const orden = App.state.ordenes_produccion.find(o => o.id === ordenId); if(!orden) return App.ui.toast("Orden no encontrada o huérfana."); const detalle = App.state.pedido_detalle.find(d => d.id === orden.pedido_detalle_id) || App.state.pedido_detalle.find(d => d.pedido_id === orden.pedido_detalle_id) || {}; const pedido = App.state.pedidos.find(p => p.id === detalle.pedido_id) || { total: 0 }; const pagos = App.state.pago_artesanos.filter(p => p.orden_id === ordenId); const costoManoObra = pagos.reduce((sum, p) => sum + parseFloat(p.total), 0); let costoMateriales = 0; try { if(orden.receta_personalizada) { const receta = JSON.parse(orden.receta_personalizada); receta.forEach(item => { const mat = App.state.inventario.find(m => m.id === item.mat_id); if(mat) costoMateriales += (parseFloat(item.cant) * parseFloat(mat.costo_unitario || 0)); }); } } catch(e) {} const totalVenta = pedido ? parseFloat(pedido.total) : 0; const utilidadNeta = totalVenta - costoMateriales - costoManoObra; let colorUtilidad = utilidadNeta > 0 ? 'var(--success)' : 'var(--danger)'; let pagosHTML = `<div style="background:#F0FFF4; padding:10px; border-radius:6px; margin-bottom:15px; border:1px solid #C6F6D5;"><h4 style="margin-bottom:5px; color:#276749;">📊 Rentabilidad de esta Hamaca</h4><div style="display:flex; justify-content:space-between; font-size:0.85rem;"><span style="color:var(--text-muted);">Precio Venta:</span> <strong>$${totalVenta.toFixed(2)}</strong></div><div style="display:flex; justify-content:space-between; font-size:0.85rem;"><span style="color:var(--danger);">- Costo Hilos:</span> <strong>$${costoMateriales.toFixed(2)}</strong></div><div style="display:flex; justify-content:space-between; font-size:0.85rem;"><span style="color:var(--danger);">- Mano de Obra:</span> <strong>$${costoManoObra.toFixed(2)}</strong></div><hr style="margin:5px 0; border-top:1px dashed #C6F6D5;"><div style="display:flex; justify-content:space-between; font-size:1.1rem; color:${colorUtilidad};"><span>Utilidad Limpia:</span> <strong>$${utilidadNeta.toFixed(2)}</strong></div></div>`; pagosHTML += '<div style="margin-bottom:15px;"><strong>🛠️ Trabajos Asignados:</strong><br>'; if(pagos.length === 0) pagosHTML += '<small style="color:var(--text-muted)">Nadie ha trabajado aún.</small>'; pagos.forEach(p => { const art = App.state.artesanos.find(a => a.id === p.artesano_id); const partesID = p.id.split('-'); const nombreTarea = partesID.length > 2 ? partesID.slice(2).join(' ') : 'Trabajo general'; pagosHTML += `<div style="display:flex; justify-content:space-between; background:#F7FAFC; padding:8px; margin-top:5px; border-radius:4px; font-size:0.85rem; border:1px solid #E2E8F0;"><span>🧑‍🎨 <strong>${art ? App.ui.escapeHTML(art.nombre) : 'Desc'}</strong> - <em>${App.ui.escapeHTML(nombreTarea)}</em></span><span><strong style="color:var(--success); margin-right:8px;">$${p.total}</strong> <span style="cursor:pointer; color:red;" onclick="App.ui.closeSheet(); App.logic.eliminarRegistroGenerico('pago_artesanos', '${p.id}', 'pago_artesanos');">🗑️</span></span></div>`; }); pagosHTML += `</div>`; pagosHTML += `<button type="button" class="btn btn-secondary" style="width:100%; margin-bottom:10px; border-style:dashed;" onclick="App.ui.closeSheet(); setTimeout(()=>App.views.formAgregarTrabajo('${ordenId}', false), 300);">+ Asignar Tarea / Artesano</button>`; pagosHTML += `<button type="button" class="btn btn-secondary" style="width:100%; margin-bottom:15px; border: 1px solid var(--primary); color: var(--primary); background: transparent;" onclick="App.logic.imprimirTicketProduccion('${ordenId}')">🖨️ Imprimir Ticket para Taller</button>`; const formHTML = `<form id="dynamic-form">${pagosHTML}<div class="form-group"><label>Estado del Pedido en Taller</label><select name="estado"><option value="pendiente" ${orden.estado === 'pendiente' ? 'selected' : ''}>Pendiente de tejer</option><option value="en_proceso" ${orden.estado === 'en_proceso' ? 'selected' : ''}>En Proceso (Tejiendo)</option><option value="listo" ${orden.estado === 'listo' ? 'selected' : ''}>¡Terminada! (Pasar a cierre)</option></select></div><button type="submit" class="btn btn-primary" style="width: 100%;">Actualizar Estado</button></form>`; App.ui.openSheet(`Orden ${ordenId}`, formHTML, (datos) => App.logic.procesarCambioOrden(ordenId, datos)); };

